# =========================
# FUNCIONES
# =========================
@st.cache_data(show_spinner=False, ttl=REMOTE_FETCH_TTL_SECONDS, persist="disk")
def fetch_remote_file_bytes(url: str, refresh_nonce: int = 0) -> bytes:
    last_error: Exception | None = None
    for attempt in range(REMOTE_FETCH_RETRIES + 1):
        try:
            response = requests.get(
                url,
                timeout=(REMOTE_CONNECT_TIMEOUT_SECONDS, REMOTE_READ_TIMEOUT_SECONDS),
                headers={"User-Agent": "streamlit-render-capex-dashboard/1.0"},
            )
            response.raise_for_status()
            return response.content
        except (requests.Timeout, requests.ConnectionError) as exc:
            last_error = exc
            if attempt >= REMOTE_FETCH_RETRIES:
                break
            time.sleep(0.8 * (attempt + 1))
    if last_error is not None:
        raise last_error
    raise RuntimeError("No se pudo descargar el archivo remoto.")


def read_remote_csv(url: str, *, refresh_nonce: int = 0, **kwargs) -> pd.DataFrame:
    return pd.read_csv(BytesIO(fetch_remote_file_bytes(url, refresh_nonce=refresh_nonce)), **kwargs)


def read_remote_excel(url: str, *, refresh_nonce: int = 0, **kwargs) -> pd.DataFrame:
    return pd.read_excel(BytesIO(fetch_remote_file_bytes(url, refresh_nonce=refresh_nonce)), **kwargs)


@st.cache_data(show_spinner=False, ttl=REMOTE_FETCH_TTL_SECONDS, persist="disk")
def load_google_pubhtml_sheet_gids(pubhtml_url: str, refresh_nonce: int = 0) -> dict[str, str]:
    content = fetch_remote_file_bytes(pubhtml_url, refresh_nonce=refresh_nonce)
    text = content.decode("utf-8", errors="replace")
    matches = re.findall(r'items\.push\(\{name: "([^"]+)"[^}]*gid: "(\d+)"', text)
    return {name: gid for name, gid in matches}


def telecom_published_csv_url(sheet_name: str, fallback_url: str, refresh_nonce: int = 0) -> str:
    try:
        gid_map = load_google_pubhtml_sheet_gids(EVALUACION_TELECOM_PUBHTML_URL, refresh_nonce=refresh_nonce)
        gid = gid_map.get(sheet_name)
        if gid:
            return f"{EVALUACION_TELECOM_PUB_BASE_URL}?gid={gid}&single=true&output=csv"
    except Exception:
        pass
    return fallback_url


def turbine_power_curve_source_csv_url(sheet_name: str, refresh_nonce: int = 0) -> str:
    gid = TURBINE_POWER_CURVE_SOURCE_SHEETS.get(sheet_name)
    try:
        gid_map = load_google_pubhtml_sheet_gids(TURBINE_POWER_CURVES_PUBHTML_URL, refresh_nonce=refresh_nonce)
        target_sheet = str(sheet_name).strip().casefold()
        for published_sheet, sheet_gid in gid_map.items():
            if str(published_sheet).strip().casefold() == target_sheet:
                gid = sheet_gid
                break
    except Exception:
        pass
    if gid:
        return f"{TURBINE_POWER_CURVES_PUB_BASE_URL}?gid={gid}&single=true&output=csv"
    return TURBINE_POWER_CURVES_PUBLISHED_CSV_URL_DEFAULT


