def clear_turbine_capex_caches() -> None:
    for cached_loader in (
        fetch_remote_file_bytes,
        load_google_pubhtml_sheet_gids,
        load_turbine_capex_supply_installation,
        load_turbine_capex_supply_models,
        load_turbine_capex_wbs_long,
        load_turbine_capex_mounting_detail,
        load_turbine_project_schedule,
        load_propuesta_catalogo_tec,
    ):
        try:
            cached_loader.clear()
        except Exception:
            pass


def parse_curve_number(value: object, default: float = np.nan) -> float:
    if pd.isna(value):
        return default
    text = str(value).strip()
    if not text or text.casefold() in {"nan", "none", "null", "-"}:
        return default
    text = text.replace("\u00a0", "").replace(" ", "")
    if "," in text:
        text = text.replace(".", "").replace(",", ".")
    elif re.fullmatch(r"-?\d{1,3}(?:\.\d{3})+(?:\.\d+)?", text):
        text = text.replace(".", "")
    text = re.sub(r"[^0-9.\-]", "", text)
    try:
        return float(text)
    except ValueError:
        return default


def _curve_sheet_value(ficha: dict[str, object], candidates: list[str], default: float = np.nan) -> float:
    for candidate in candidates:
        value = ficha.get(normalize_key(candidate))
        parsed = parse_curve_number(value, default=np.nan)
        if np.isfinite(parsed):
            return float(parsed)
    return default


def _curve_ficha_by_model(raw: pd.DataFrame) -> dict[str, dict[str, object]]:
    if raw is None or raw.empty:
        return {}

    header_idx = None
    for idx in range(len(raw.index)):
        first_cell = clean_sheet_cell(raw.iat[idx, 0]) if raw.shape[1] else ""
        if normalize_key(first_cell) == normalize_key("Parámetro"):
            header_idx = idx
            break
    if header_idx is None:
        return {}

    headers = [clean_sheet_cell(value) for value in raw.iloc[header_idx].tolist()]
    allowed_columns = {normalize_key(meta["curve_column"]) for meta in TURBINE_POWER_CURVE_SHEETS.values()}
    turbine_cols = [
        (col_idx, label)
        for col_idx, label in enumerate(headers)
        if col_idx > 0 and normalize_key(label) in allowed_columns
    ]
    ficha: dict[str, dict[str, object]] = {label: {} for _, label in turbine_cols}

    for row_idx in range(header_idx + 1, len(raw.index)):
        param = clean_sheet_cell(raw.iat[row_idx, 0]) if raw.shape[1] else ""
        param_key = normalize_key(param)
        if not param_key:
            continue
        for col_idx, label in turbine_cols:
            if col_idx < raw.shape[1]:
                ficha[label][param_key] = raw.iat[row_idx, col_idx]
    return ficha


def _curve_table_from_resumen(raw: pd.DataFrame) -> pd.DataFrame:
    if raw is None or raw.empty:
        return pd.DataFrame()

    header_idx = None
    for idx in range(len(raw.index)):
        first_cell = clean_sheet_cell(raw.iat[idx, 0]) if raw.shape[1] else ""
        if normalize_key(first_cell) == normalize_key("V (m/s)"):
            header_idx = idx
            break
    if header_idx is None:
        return pd.DataFrame()

    headers = [clean_sheet_cell(value) for value in raw.iloc[header_idx].tolist()]
    table = raw.iloc[header_idx + 1 :].copy()
    table = table.iloc[:, : len(headers)]
    table.columns = headers
    table = table[table[headers[0]].map(lambda value: np.isfinite(parse_curve_number(value, default=np.nan)))].copy()
    if table.empty:
        return pd.DataFrame()
    return table.reset_index(drop=True)


def _turbine_capex_model_key(value: object) -> str | None:
    key = normalize_key(clean_sheet_cell(value))
    if not key:
        return None
    if any(token in key for token in ["500w", "gv500", "gv0500", "05kw", "0p5kw"]):
        return "VAWT 0.5 kW"
    if "10" in key and any(token in key for token in ["ghv", "gvh", "vawt", "gv"]):
        return "VAWT 10 kW"
    if "5" in key and any(token in key for token in ["ghv", "gvh", "vawt", "gv"]):
        return "VAWT 5 kW"
    if "3" in key and any(token in key for token in ["ghv", "gvh", "vawt", "gv"]):
        return "VAWT 3 kW"
    if "1" in key and "10" not in key and any(token in key for token in ["ghv", "gvh", "vawt", "gv"]):
        return "VAWT 1 kW"
    if "80" in key and any(token in key for token in ["ghv", "gvh", "vawt", "gv"]):
        return "VAWT 80 kW"
    return None


@st.cache_data(show_spinner=False, ttl=REMOTE_FETCH_TTL_SECONDS, persist="disk")
def load_turbine_capex_defaults_from_resumen(refresh_nonce: int = 0) -> dict[str, float]:
    raw = read_remote_csv(
        turbine_capex_resumen_csv_url("00_Resumen", refresh_nonce=refresh_nonce),
        refresh_nonce=refresh_nonce + TURBINE_CAPEX_RESUMEN_SOURCE_VERSION,
        dtype=str,
        header=None,
    ).fillna("")
    capex_by_model: dict[str, float] = {}

    header_idx = None
    model_col_idx = None
    capex_col_idx = None
    preferred_capex_keys = [
        normalize_key("Sistema CLP Venta"),
        normalize_key("Sistema CLP"),
        normalize_key("CAPEX unitario"),
    ]
    for idx in range(len(raw.index)):
        row_values = [clean_sheet_cell(value) for value in raw.iloc[idx].tolist()]
        row_keys = [normalize_key(value) for value in row_values]
        if normalize_key("Modelo") not in row_keys:
            continue
        header_idx = idx
        model_col_idx = row_keys.index(normalize_key("Modelo"))
        for preferred in preferred_capex_keys:
            if preferred in row_keys:
                capex_col_idx = row_keys.index(preferred)
                break
        if capex_col_idx is None and raw.shape[1] > 7:
            capex_col_idx = 7  # Columna H como respaldo explícito del archivo fuente.
        break

    if header_idx is not None and model_col_idx is not None and capex_col_idx is not None:
        for row_idx in range(header_idx + 1, len(raw.index)):
            model_key = _turbine_capex_model_key(raw.iat[row_idx, model_col_idx])
            if not model_key or capex_col_idx >= raw.shape[1]:
                continue
            parsed = parse_money_clp_robusto(clean_sheet_cell(raw.iat[row_idx, capex_col_idx]))
            if parsed and parsed > 0:
                capex_by_model[model_key] = float(parsed)
        if capex_by_model:
            return capex_by_model

    capex_col_idx = 7  # Columna H en Google Sheets.
    capex_start_row_idx = 11  # Fila 12 en Google Sheets.
    for offset, model in enumerate(TURBINE_CAPEX_RESUMEN_ROW_MODEL_ORDER):
        row_idx = capex_start_row_idx + offset
        if row_idx >= raw.shape[0] or capex_col_idx >= raw.shape[1]:
            continue
        raw_value = clean_sheet_cell(raw.iat[row_idx, capex_col_idx])
        parsed = parse_money_clp_robusto(raw_value)
        if parsed and parsed > 0:
            capex_by_model[model] = float(parsed)
    return capex_by_model


@st.cache_data(show_spinner=False, ttl=CAPEX_REMOTE_FETCH_TTL_SECONDS, persist="disk")
def load_turbine_capex_supply_installation(refresh_nonce: int = 0) -> pd.DataFrame:
    raw = read_remote_csv(
        turbine_capex_supply_installation_csv_url("00_Resumen", refresh_nonce=refresh_nonce),
        refresh_nonce=refresh_nonce + TURBINE_CAPEX_SUPPLY_INSTALLATION_SOURCE_VERSION,
        dtype=str,
        header=None,
    ).fillna("")

    header_idx = None
    capex_total_keys = {
        normalize_key("CAPEX instalado total"),
        normalize_key("Total instalado CLP"),
        normalize_key("Total instalado US$ eq."),
    }
    for idx in range(len(raw.index)):
        row_values = [clean_sheet_cell(value) for value in raw.iloc[idx].tolist()]
        row_keys = {normalize_key(value) for value in row_values if value}
        if normalize_key("Modelo") in row_keys and row_keys.intersection(capex_total_keys):
            header_idx = idx
            break
    if header_idx is None:
        return pd.DataFrame()

    headers = [clean_sheet_cell(value) or f"Campo {col_idx + 1}" for col_idx, value in enumerate(raw.iloc[header_idx].tolist())]
    records = []
    for row_idx in range(header_idx + 1, len(raw.index)):
        values = [clean_sheet_cell(value) for value in raw.iloc[row_idx].tolist()]
        if not any(values):
            continue
        model_key = _turbine_capex_model_key(values[0] if values else "")
        if not model_key:
            continue
        records.append({headers[col_idx]: values[col_idx] if col_idx < len(values) else "" for col_idx in range(len(headers))})
    if not records:
        return pd.DataFrame()

    df = pd.DataFrame(records)

    def col(candidates: list[str]) -> str | None:
        return first_matching_column(df, candidates)

    def exact_col(candidates: list[str]) -> str | None:
        candidate_keys = {normalize_key(candidate) for candidate in candidates}
        for column_name in df.columns:
            if normalize_key(column_name) in candidate_keys:
                return column_name
        return None

    model_col = col(["Modelo"])
    potencia_col = col(["Potencia kW", "Potencia instalada kW"])
    suministro_usd_col = exact_col(["Suministro US$ ref.", "Suministro USD"])
    suministro_clp_col = exact_col(["Suministro CLP"])
    montaje_usd_col = exact_col(["CAPEX montaje sin suministro USD", "Montaje US$ ref.", "Montaje USD"])
    montaje_clp_col = exact_col(["Montaje CLP"])
    total_usd_col = col(["Total instalado US$ eq.", "CAPEX instalado total", "CAPEX instalado USD", "Total instalado USD"])
    total_clp_col = col(["Total instalado CLP", "CAPEX instalado CLP"])
    factor_col = col(["Factor instalación", "Factor instalacion"])
    pct_montaje_col = exact_col(["% montaje", "% montaje sobre total", "montaje sobre total"])
    usd_kw_col = col(["CAPEX instalado USD/kW"])
    clp_kw_col = col(["CAPEX instalado CLP/kW"])
    montaje_usd_kw_col = col(["CAPEX montaje USD/kW"])
    montaje_clp_kw_col = col(["CAPEX montaje CLP/kW"])

    def numeric_series(column_name: str | None, parser=parse_money_clp_robusto) -> pd.Series:
        if not column_name:
            return pd.Series(np.nan, index=df.index, dtype="float64")
        return pd.to_numeric(df[column_name].map(parser), errors="coerce")

    normalized = pd.DataFrame()
    normalized["Modelo fuente"] = df[model_col].map(clean_sheet_cell) if model_col else ""
    normalized["Modelo"] = normalized["Modelo fuente"].map(_turbine_capex_model_key)
    normalized["Potencia kW"] = numeric_series(potencia_col, parse_model_number)
    normalized["CAPEX instalado total USD"] = numeric_series(total_usd_col, parse_model_number)
    normalized["CAPEX instalado CLP"] = numeric_series(total_clp_col, parse_money_clp_robusto)
    fx_rate = np.where(
        normalized["CAPEX instalado total USD"] > 0,
        normalized["CAPEX instalado CLP"] / normalized["CAPEX instalado total USD"],
        np.nan,
    )
    suministro_usd = numeric_series(suministro_usd_col, parse_model_number)
    suministro_clp = numeric_series(suministro_clp_col, parse_money_clp_robusto)
    montaje_usd = numeric_series(montaje_usd_col, parse_model_number)
    montaje_clp = numeric_series(montaje_clp_col, parse_money_clp_robusto)
    normalized["CAPEX suministro CLP"] = suministro_clp.fillna(pd.Series(np.where(fx_rate > 0, suministro_usd * fx_rate, np.nan), index=df.index))
    normalized["CAPEX montaje sin suministro CLP"] = montaje_clp.fillna(pd.Series(np.where(fx_rate > 0, montaje_usd * fx_rate, np.nan), index=df.index))
    normalized["CAPEX suministro USD"] = suministro_usd.fillna(pd.Series(np.where(fx_rate > 0, suministro_clp / fx_rate, np.nan), index=df.index))
    normalized["CAPEX montaje sin suministro USD"] = montaje_usd.fillna(pd.Series(np.where(fx_rate > 0, montaje_clp / fx_rate, np.nan), index=df.index))
    normalized["Factor instalación"] = numeric_series(factor_col, parse_model_number)
    normalized["Montaje sobre total %"] = df[pct_montaje_col].map(lambda value: parse_model_percent(value) * 100.0) if pct_montaje_col else np.nan
    installed_usd_kw = numeric_series(usd_kw_col, parse_money_clp_robusto)
    installed_clp_kw = numeric_series(clp_kw_col, parse_money_clp_robusto)
    mounted_usd_kw = numeric_series(montaje_usd_kw_col, parse_money_clp_robusto)
    mounted_clp_kw = numeric_series(montaje_clp_kw_col, parse_money_clp_robusto)
    normalized["CAPEX instalado USD/kW"] = installed_usd_kw.fillna(
        pd.Series(np.where(fx_rate > 0, installed_clp_kw / fx_rate, np.nan), index=df.index)
    )
    normalized["CAPEX instalado USD/kW"] = normalized["CAPEX instalado USD/kW"].fillna(
        pd.Series(
            np.where(normalized["Potencia kW"] > 0, normalized["CAPEX instalado total USD"] / normalized["Potencia kW"], np.nan),
            index=normalized.index,
        )
    )
    normalized["CAPEX montaje USD/kW"] = mounted_usd_kw.fillna(
        pd.Series(np.where(fx_rate > 0, mounted_clp_kw / fx_rate, np.nan), index=df.index)
    )
    normalized["CAPEX montaje USD/kW"] = normalized["CAPEX montaje USD/kW"].fillna(
        pd.Series(
            np.where(normalized["Potencia kW"] > 0, normalized["CAPEX montaje sin suministro USD"] / normalized["Potencia kW"], np.nan),
            index=normalized.index,
        )
    )
    normalized = normalized[normalized["Modelo"].notna()].copy()
    suministro_pct = np.where(
        pd.to_numeric(normalized["CAPEX instalado total USD"], errors="coerce") > 0,
        pd.to_numeric(normalized["CAPEX suministro USD"], errors="coerce") / pd.to_numeric(normalized["CAPEX instalado total USD"], errors="coerce") * 100.0,
        np.nan,
    )
    normalized["Suministro sobre total %"] = pd.Series(suministro_pct, index=normalized.index).fillna(100.0 - normalized["Montaje sobre total %"])
    normalized["Montaje / suministro x"] = np.where(
        pd.to_numeric(normalized["CAPEX suministro USD"], errors="coerce") > 0,
        pd.to_numeric(normalized["CAPEX montaje sin suministro USD"], errors="coerce") / pd.to_numeric(normalized["CAPEX suministro USD"], errors="coerce"),
        np.nan,
    )
    order = {model: idx for idx, model in enumerate(["VAWT 0.5 kW", "VAWT 1 kW", "VAWT 3 kW", "VAWT 5 kW", "VAWT 10 kW", "VAWT 80 kW"])}
    normalized["_order"] = normalized["Modelo"].map(order).fillna(999)
    return normalized.sort_values(["_order", "Potencia kW"]).drop(columns="_order").reset_index(drop=True)


@st.cache_data(show_spinner=False, ttl=CAPEX_REMOTE_FETCH_TTL_SECONDS, persist="disk")
def load_turbine_capex_supply_models(refresh_nonce: int = 0) -> pd.DataFrame:
    raw = read_remote_csv(
        turbine_capex_supply_installation_csv_url("01_Modelos", refresh_nonce=refresh_nonce),
        refresh_nonce=refresh_nonce + TURBINE_CAPEX_SUPPLY_INSTALLATION_SOURCE_VERSION,
        dtype=str,
        header=None,
    ).fillna("")
    header_idx = None
    for idx in range(len(raw.index)):
        row_values = [clean_sheet_cell(value) for value in raw.iloc[idx].tolist()]
        row_keys = {normalize_key(value) for value in row_values if value}
        if normalize_key("Modelo") in row_keys and normalize_key("Paquete completo EXW") in row_keys:
            header_idx = idx
            break
    if header_idx is None:
        return pd.DataFrame()
    headers = [clean_sheet_cell(value) or f"Campo {col_idx + 1}" for col_idx, value in enumerate(raw.iloc[header_idx].tolist())]
    rows = []
    for row_idx in range(header_idx + 1, len(raw.index)):
        values = [clean_sheet_cell(value) for value in raw.iloc[row_idx].tolist()]
        if not any(values):
            continue
        source_model = values[0] if values else ""
        model_key = _turbine_capex_model_key(source_model)
        if not model_key:
            continue
        record = {headers[col_idx]: values[col_idx] if col_idx < len(values) else "" for col_idx in range(len(headers))}
        record["Modelo"] = model_key
        record["Modelo fuente"] = source_model
        rows.append(record)
    if not rows:
        return pd.DataFrame()
    df = pd.DataFrame(rows)
    for col in ["Potencia kW", "Turbina", "Controlador MPPT", "Inversor", "Torre / Mástil", "DTU", "Batería LiFePO4", "Paquete completo EXW", "USD/kW EXW"]:
        if col in df.columns:
            df[col] = df[col].map(parse_money_clp_robusto if col != "Potencia kW" else parse_model_number)
    return df.reset_index(drop=True)


@st.cache_data(show_spinner=False, ttl=CAPEX_REMOTE_FETCH_TTL_SECONDS, persist="disk")
def load_turbine_capex_wbs_long(refresh_nonce: int = 0) -> pd.DataFrame:
    raw = read_remote_csv(
        turbine_capex_supply_installation_csv_url("03_CAPEX_WBS_USD_CLP", refresh_nonce=refresh_nonce),
        refresh_nonce=refresh_nonce + TURBINE_CAPEX_SUPPLY_INSTALLATION_SOURCE_VERSION,
        dtype=str,
        header=None,
    ).fillna("")
    header_idx = None
    for idx in range(len(raw.index)):
        row_values = [clean_sheet_cell(value) for value in raw.iloc[idx].tolist()]
        row_keys = {normalize_key(value) for value in row_values if value}
        if normalize_key("Nivel") in row_keys and normalize_key("Partida") in row_keys and normalize_key("Clasificación") in row_keys:
            header_idx = idx
            break
    if header_idx is None:
        return pd.DataFrame()
    headers = [clean_sheet_cell(value) or f"Campo {col_idx + 1}" for col_idx, value in enumerate(raw.iloc[header_idx].tolist())]
    df = raw.iloc[header_idx + 1 :].copy()
    df = df.iloc[:, : len(headers)]
    df.columns = headers
    criterio_resumen_col = first_matching_column(df, ["Criterio Resumen", "Criterio resumen", "Resumen"])
    criterio_calculo_col = first_matching_column(df, ["Criterio cálculo", "Criterio calculo", "Cálculo", "Calculo"])
    model_cols = [col for col in df.columns if _turbine_capex_model_key(col)]
    if not model_cols:
        return pd.DataFrame()
    rows = []
    current_section = "Resumen CAPEX"
    for _, row in df.iterrows():
        nivel = clean_sheet_cell(row.get("Nivel", ""))
        partida = clean_sheet_cell(row.get("Partida", ""))
        clasificacion = clean_sheet_cell(row.get("Clasificación", ""))
        if not partida:
            continue
        row_type = "Detalle"
        if normalize_key(clasificacion) == "total":
            row_type = "Total"
        elif normalize_key(clasificacion) == "subtotal":
            row_type = "Subtotal"
        elif normalize_key(clasificacion) == "kpi":
            row_type = "KPI"
        if not nivel and row_type in {"Total", "Subtotal", "KPI"}:
            current_section = partida
        for model_col in model_cols:
            model_key = _turbine_capex_model_key(model_col)
            raw_value = clean_sheet_cell(row.get(model_col, ""))
            amount = parse_money_clp_robusto(raw_value)
            pct_value = parse_model_percent(raw_value) * 100.0 if "%" in raw_value else np.nan
            factor_value = parse_model_number(raw_value) if "x" in raw_value.lower() else np.nan
            rows.append(
                {
                    "Modelo": model_key,
                    "Modelo fuente": model_col,
                    "Nivel": nivel,
                    "Partida": partida,
                    "Clasificación": clasificacion,
                    "Sección": current_section,
                    "Tipo fila": row_type,
                    "Monto USD": float(amount or 0.0),
                    "Monto CLP": float(amount or 0.0),
                    "Porcentaje": pct_value,
                    "Factor": factor_value,
                    "Valor bruto": raw_value,
                    "Criterio Resumen": clean_sheet_cell(row.get(criterio_resumen_col, "")) if criterio_resumen_col else "",
                    "Criterio cálculo": clean_sheet_cell(row.get(criterio_calculo_col, "")) if criterio_calculo_col else "",
                    "Criterio": clean_sheet_cell(row.get(criterio_resumen_col, "")) if criterio_resumen_col else "",
                    "Nota": clean_sheet_cell(row.get("Nota", "")),
                }
            )
    return pd.DataFrame(rows)


@st.cache_data(show_spinner=False, ttl=CAPEX_REMOTE_FETCH_TTL_SECONDS, persist="disk")
def load_turbine_capex_mounting_detail(refresh_nonce: int = 0) -> pd.DataFrame:
    raw = read_remote_csv(
        turbine_capex_supply_installation_csv_url("04_Montaje_Detalle_CLP", refresh_nonce=refresh_nonce),
        refresh_nonce=refresh_nonce + TURBINE_CAPEX_SUPPLY_INSTALLATION_SOURCE_VERSION,
        dtype=str,
        header=None,
    ).fillna("")
    header_idx = None
    for idx in range(len(raw.index)):
        row_values = [clean_sheet_cell(value) for value in raw.iloc[idx].tolist()]
        row_keys = {normalize_key(value) for value in row_values if value}
        if normalize_key("ID") in row_keys and normalize_key("Modelo") in row_keys and normalize_key("Costo total CLP") in row_keys:
            header_idx = idx
            break
    if header_idx is None:
        return pd.DataFrame()

    headers = [clean_sheet_cell(value) or f"Campo {col_idx + 1}" for col_idx, value in enumerate(raw.iloc[header_idx].tolist())]
    df = raw.iloc[header_idx + 1 :].copy()
    df = df.iloc[:, : len(headers)]
    df.columns = headers
    df = df[df["ID"].map(clean_sheet_cell).astype(bool)].copy() if "ID" in df.columns else df
    if df.empty:
        return pd.DataFrame()

    def detail_col(candidates: list[str]) -> str | None:
        candidate_keys = {normalize_key(candidate) for candidate in candidates}
        for column_name in df.columns:
            if normalize_key(column_name) in candidate_keys:
                return column_name
        return first_matching_column(df, candidates)

    model_col = detail_col(["Modelo"])
    if not model_col:
        return pd.DataFrame()

    numeric_specs = {
        "Potencia kW": (detail_col(["Potencia kW"]), parse_model_number),
        "N° turbinas sitio": (detail_col(["N° turbinas sitio", "N turbinas sitio"]), parse_model_number),
        "EXW unitario US$": (detail_col(["EXW unitario US$"]), parse_model_number),
        "Cantidad recurso": (detail_col(["Cantidad recurso"]), parse_model_number),
        "Personas": (detail_col(["Personas"]), parse_model_number),
        "Días": (detail_col(["Días", "Dias"]), parse_model_number),
        "Horas/día": (detail_col(["Horas/día", "Horas dia"]), parse_model_number),
        "Tarifa CLP / Factor %": (detail_col(["Tarifa CLP / Factor %", "Tarifa"]), parse_float_local),
        "Factor modelo": (detail_col(["Factor modelo"]), parse_model_number),
        "Factor sitio": (detail_col(["Factor sitio"]), parse_model_number),
        "Costo base CLP": (detail_col(["Costo base CLP"]), parse_money_clp_robusto),
        "Costo total CLP": (detail_col(["Costo total CLP"]), parse_money_clp_robusto),
        "Base indirectos CLP": (detail_col(["Base indirectos CLP"]), parse_money_clp_robusto),
        "Base imprevistos CLP": (detail_col(["Base imprevistos CLP"]), parse_money_clp_robusto),
    }

    normalized = pd.DataFrame()
    text_columns = [
        "ID",
        "WBS destino",
        "Partida WBS destino",
        "Área",
        "Actividad",
        "Tipo costo",
        "Recurso",
        "Unidad",
        "Tipo cálculo",
        "Fuente / supuesto",
        "Revisión",
        "Base indirectos",
    ]
    for output_col in text_columns:
        source_col = detail_col([output_col])
        normalized[output_col] = df[source_col].map(clean_sheet_cell) if source_col else ""

    normalized["Modelo fuente"] = df[model_col].map(clean_sheet_cell)
    normalized["Modelo"] = normalized["Modelo fuente"].map(_turbine_capex_model_key)
    for output_col, (source_col, parser) in numeric_specs.items():
        normalized[output_col] = pd.to_numeric(df[source_col].map(parser), errors="coerce") if source_col else np.nan
    normalized["HH calculadas"] = normalized["Personas"].fillna(0) * normalized["Días"].fillna(0) * normalized["Horas/día"].fillna(0)
    normalized["Factor combinado"] = normalized["Factor modelo"].fillna(1) * normalized["Factor sitio"].fillna(1)
    normalized = normalized[normalized["Modelo"].notna()].copy()
    return normalized.reset_index(drop=True)


@st.cache_data(show_spinner=False, ttl=CAPEX_REMOTE_FETCH_TTL_SECONDS, persist="disk")
def load_turbine_project_schedule(refresh_nonce: int = 0) -> tuple[pd.DataFrame, dict[str, str]]:
    raw = read_remote_csv(
        turbine_capex_supply_installation_csv_url("07_Cronograma_Ejecucion", refresh_nonce=refresh_nonce),
        refresh_nonce=refresh_nonce + TURBINE_CAPEX_SUPPLY_INSTALLATION_SOURCE_VERSION,
        dtype=str,
        header=None,
    ).fillna("")

    meta: dict[str, str] = {"Título": clean_sheet_cell(raw.iat[0, 0]) if raw.shape[0] and raw.shape[1] else ""}
    for row_idx in range(min(11, raw.shape[0])):
        row_values = [clean_sheet_cell(value) for value in raw.iloc[row_idx].tolist()]
        for col_idx in range(0, min(len(row_values) - 1, 14), 2):
            label = row_values[col_idx]
            value = row_values[col_idx + 1] if col_idx + 1 < len(row_values) else ""
            if label and value:
                meta[label] = value
        if len(row_values) > 2 and row_values[0] and row_values[2]:
            meta[row_values[0]] = row_values[2]
        if len(row_values) > 5 and row_values[4] and row_values[5]:
            meta[row_values[4]] = row_values[5]

    header_idx = None
    for idx in range(len(raw.index)):
        row_values = [clean_sheet_cell(value) for value in raw.iloc[idx].tolist()]
        row_keys = {normalize_key(value) for value in row_values if value}
        if normalize_key("ID") in row_keys and normalize_key("Actividad") in row_keys and normalize_key("Inicio día") in row_keys:
            header_idx = idx
            break
    if header_idx is None:
        return pd.DataFrame(), meta

    headers = [clean_sheet_cell(value) or f"Campo {col_idx + 1}" for col_idx, value in enumerate(raw.iloc[header_idx].tolist())]
    df = raw.iloc[header_idx + 1 :].copy()
    df = df.iloc[:, : len(headers)]
    df.columns = headers
    if "ID" in df.columns:
        df = df[df["ID"].map(clean_sheet_cell).astype(bool)].copy()
    if df.empty:
        return pd.DataFrame(), meta

    def schedule_col(candidates: list[str]) -> str | None:
        candidate_keys = {normalize_key(candidate) for candidate in candidates}
        for column_name in df.columns:
            if normalize_key(column_name) in candidate_keys:
                return column_name
        return first_matching_column(df, candidates)

    numeric_specs = {
        "Inicio día": schedule_col(["Inicio día", "Inicio dia", "Inicio"]),
        "Duración": schedule_col(["Duración", "Duracion", "Días", "Dias"]),
        "Fin día": schedule_col(["Fin día", "Fin dia", "Fin"]),
    }
    text_specs = {
        "ID": schedule_col(["ID"]),
        "Bloque": schedule_col(["Bloque"]),
        "Alcance": schedule_col(["Alcance"]),
        "Actividad": schedule_col(["Actividad"]),
        "Predecesora": schedule_col(["Predecesora", "Predecesoras"]),
        "Solape": schedule_col(["Solape"]),
        "Ruta crítica": schedule_col(["Ruta crítica", "Ruta critica"]),
        "Responsable": schedule_col(["Responsable"]),
        "Entregable técnico": schedule_col(["Entregable técnico", "Entregable tecnico", "Entregable"]),
        "Criterio aceptación / supuesto": schedule_col(["Criterio aceptación / supuesto", "Criterio aceptacion / supuesto", "Criterio"]),
        "Riesgo / control": schedule_col(["Riesgo / control", "Riesgo"]),
        "Nota": schedule_col(["Nota"]),
    }

    normalized = pd.DataFrame()
    for output_col, source_col in text_specs.items():
        normalized[output_col] = df[source_col].map(clean_sheet_cell) if source_col else ""
    for output_col, source_col in numeric_specs.items():
        normalized[output_col] = pd.to_numeric(df[source_col].map(parse_model_number), errors="coerce") if source_col else np.nan

    normalized["Duración"] = normalized["Duración"].fillna(1).clip(lower=1)
    normalized["Inicio día"] = normalized["Inicio día"].fillna(1).clip(lower=1)
    normalized["Fin día"] = normalized["Fin día"].fillna(normalized["Inicio día"] + normalized["Duración"] - 1)
    normalized["Duración calculada"] = (normalized["Fin día"] - normalized["Inicio día"] + 1).clip(lower=1)
    normalized["Tiene solape"] = normalized["Solape"].map(lambda value: normalize_key(value) in {"si", "sí", "yes", "true"})
    normalized["Es ruta crítica"] = normalized["Ruta crítica"].map(lambda value: normalize_key(value) in {"si", "sí", "yes", "true"})
    normalized["Orden"] = np.arange(len(normalized)) + 1
    normalized["Etiqueta"] = normalized["ID"].astype(str) + " · " + normalized["Actividad"].astype(str).map(lambda value: textwrap.shorten(value, width=58, placeholder="..."))
    normalized["Día medio"] = normalized["Inicio día"] + normalized["Duración calculada"] / 2.0
    normalized = normalized.sort_values(["Inicio día", "Fin día", "Orden"]).reset_index(drop=True)
    return normalized, meta


@st.cache_data(show_spinner=False, ttl=REMOTE_FETCH_TTL_SECONDS, persist="disk")
def load_turbine_power_curves(refresh_nonce: int = 0) -> dict[str, dict]:
    curves: dict[str, dict] = {}
    resumen_raw = read_remote_csv(
        turbine_power_curve_source_csv_url("00_Resumen", refresh_nonce=refresh_nonce),
        refresh_nonce=refresh_nonce + TURBINE_POWER_CURVES_SOURCE_VERSION,
        dtype=str,
        header=None,
    ).fillna("")
    ficha_raw = read_remote_csv(
        turbine_power_curve_source_csv_url("02_Ficha_GREEF", refresh_nonce=refresh_nonce),
        refresh_nonce=refresh_nonce + TURBINE_POWER_CURVES_SOURCE_VERSION,
        dtype=str,
        header=None,
    ).fillna("")
    curve_table = _curve_table_from_resumen(resumen_raw)
    ficha_by_model = _curve_ficha_by_model(ficha_raw)
    if curve_table.empty:
        return curves

    speed_col = curve_table.columns[0]
    for model, meta in TURBINE_POWER_CURVE_SHEETS.items():
        curve_column = str(meta.get("curve_column", meta.get("sheet", ""))).strip()
        if curve_column not in curve_table.columns:
            continue
        curve = pd.DataFrame(
            {
                "Velocidad m/s": curve_table[speed_col].map(parse_curve_number),
                "Potencia kW": curve_table[curve_column].map(parse_curve_number),
            }
        ).dropna(subset=["Velocidad m/s", "Potencia kW"])
        curve = curve[(curve["Velocidad m/s"] >= 0) & (curve["Potencia kW"] >= 0)].copy()
        if curve.empty:
            continue
        curve = curve.sort_values("Velocidad m/s").drop_duplicates("Velocidad m/s", keep="last").reset_index(drop=True)
        ficha = ficha_by_model.get(curve_column, {})
        rated_kw = _curve_sheet_value(ficha, ["Potencia nominal Pn"], float(meta.get("rated_kw", np.nan)))
        tower_height_m = _curve_sheet_value(ficha, ["Altura torre"], np.nan)
        blade_length_m = _curve_sheet_value(ficha, ["Largo de pala", "Blades Length"], np.nan)
        rotor_area_m2 = _curve_sheet_value(ficha, ["Área barrida A", "Area barrida A"], np.nan)
        air_density = _curve_sheet_value(ficha, ["rho", "ρ aire", "densidad aire"], 1.225)
        curves[model] = {
            "model": model,
            "sheet": f"00_Resumen · {curve_column}",
            "rated_kw": rated_kw,
            "rotor_height_m": blade_length_m,
            "total_height_m": tower_height_m,
            "effective_wind_height_m": tower_height_m,
            "rotor_diameter_m": _curve_sheet_value(ficha, ["Diámetro rotor", "Diametro rotor"], np.nan),
            "rotor_area_m2": rotor_area_m2,
            "air_density": air_density if np.isfinite(air_density) and air_density > 0 else 1.225,
            "cp_sheet": _curve_sheet_value(ficha, ["Cp aparente nominal", "Cp nominal"], np.nan),
            "eta_sheet": _curve_sheet_value(ficha, ["Eficiencia", "η"], np.nan),
            "cut_in_ms": _curve_sheet_value(ficha, ["V cut-in efectivo", "Velocidad de arranque"], np.nan),
            "cut_out_ms": _curve_sheet_value(ficha, ["Velocidad trabajo máxima"], np.nan),
            "vnom_ms": _curve_sheet_value(ficha, ["Velocidad nominal Vnom"], np.nan),
            "engineering_flag": clean_sheet_cell(ficha.get(normalize_key("Flag ingeniería"), "")),
            "curve": curve,
        }
    return curves


