                hovertemplate="<b>%{x}</b><br>Generación: %{y:,.0f} kWh<br>Cubierto: %{customdata[0]:,.0f} kWh<br>Excedente: %{customdata[1]:,.0f} kWh<br>Brecha: %{customdata[2]:,.0f} kWh<br>Cobertura: %{customdata[3]:.0f}%<extra></extra>",
