    def _set_site_data_value(variable: str, value: str, unit: str = "", source: str = "03_Boleta_Carga", comment: str = "") -> None:
        nonlocal site_data
        mask = site_data["Variable"].astype(str).str.casefold() == variable.casefold()
        if mask.any():
            site_data.loc[mask, "Valor"] = value
            if unit:
                site_data.loc[mask, "Unidad"] = unit
            site_data.loc[mask, "Fuente requerida"] = source
            site_data.loc[mask, "Estado"] = "Automático"
            if comment:
                site_data.loc[mask, "Comentario"] = comment
            return
        site_data = pd.concat(
            [
                site_data,
                pd.DataFrame(
                    [
                        {
                            "Sección": "Consumo, suministro y costos energéticos",
                            "Variable": variable,
                            "Valor": value,
                            "Unidad": unit,
                            "Fuente requerida": source,
                            "Uso": "Dimensionamiento",
                            "Estado": "Automático",
                            "Comentario": comment,
                            "Prioridad": "Alta",
                        }
                    ]
                ),
            ],
            ignore_index=True,
        )

    billing_monthly_model = parse_float_local(billing_summary.get("Consumo mensual modelo", np.nan), np.nan)
    if np.isfinite(billing_monthly_model) and billing_monthly_model > 0:
        _set_site_data_value(
            "Consumo mensual modelo",
            f"{billing_monthly_model:,.0f}".replace(",", "."),
            "kWh/mes",
            "03_Boleta_Carga",
            "Sincronizado desde resumen de boleta publicada.",
        )
        _set_site_data_value(
            "Consumo anual",
            f"{billing_monthly_model * 12:,.0f}".replace(",", "."),
            "kWh/año",
            "Calculado",
            "Consumo mensual modelo x 12.",
        )

    site_sections = {name: group.reset_index(drop=True) for name, group in site_data.groupby("Sección", sort=False)}

    def site_value(variable: str, default: str = "") -> str:
        matches = site_data[site_data["Variable"].astype(str).str.casefold() == variable.casefold()]
        if matches.empty:
            return default
        value = str(matches.iloc[0].get("Valor", "")).strip()
        return value if value else default

    def site_numeric(variable: str, default: float = 0.0) -> float:
        value = site_value(variable, "")
        money = parse_money_clp_robusto(value)
        if money:
            return float(money)
        return parse_float_local(value, default)

    def site_percent_value(variable: str, default_pct: float = 0.0) -> float:
        value = site_value(variable, "")
        if "%" in value:
            return parse_percent_local(value, default_pct / 100.0) * 100.0
        return parse_float_local(value, default_pct)

    wind_csv_outputs = st.session_state.get("telecom_09_viento_outputs", {})
    wind_csv_bridge_fp = np.nan
    if isinstance(wind_csv_outputs, dict) and wind_csv_outputs:
        wind_csv_bridge_fp = float(wind_csv_outputs.get("factor_planta_recomendado", np.nan))
    wind_csv_bridge_active = bool(np.isfinite(wind_csv_bridge_fp) and wind_csv_bridge_fp > 0)
    if wind_csv_bridge_active and isinstance(wind_csv_outputs, dict) and wind_csv_outputs:
        bridge_fp = wind_csv_bridge_fp
        bridge_speed = float(wind_csv_outputs.get("velocidad_media_recomendada", np.nan))
        bridge_energy = float(wind_csv_outputs.get("energia_anual_neta_por_turbina", np.nan))
        bridge_column = str(wind_csv_outputs.get("altura_columna_recomendada", "09_Viento")).strip() or "09_Viento"
        bridge_class = str(wind_csv_outputs.get("clasificacion_recurso", "")).strip()
        if np.isfinite(bridge_fp) and bridge_fp > 0 and not wind_df.empty and "Potencia unitaria kW" in wind_df.columns:
            wind_df = wind_df.copy()
            potency = pd.to_numeric(wind_df["Potencia unitaria kW"], errors="coerce").fillna(0.0)
            if "Nº turbinas requerido" in wind_df.columns:
                turbines = pd.to_numeric(wind_df["Nº turbinas requerido"], errors="coerce").fillna(1.0).clip(lower=1.0)
            else:
                turbines = pd.Series(1.0, index=wind_df.index)
            generation_month_per_turbine = potency * 8760.0 * (bridge_fp / 100.0) / 12.0
            generation_month_total = generation_month_per_turbine * turbines
            consumption_month = site_numeric("Consumo mensual modelo", np.nan)
            wind_df["Factor planta"] = bridge_fp
            wind_df["Generación mensual/turbina kWh"] = generation_month_per_turbine
            wind_df["Generación mensual total kWh"] = generation_month_total
            if np.isfinite(consumption_month) and consumption_month > 0:
                wind_df["Energía útil anual kWh"] = np.minimum(generation_month_total, consumption_month) * 12.0
                wind_df["Cobertura real"] = generation_month_total / consumption_month * 100.0
                wind_df["Remanente anual kWh"] = np.maximum(generation_month_total - consumption_month, 0.0) * 12.0
            if "Dato crítico a validar" not in wind_df.columns:
                wind_df["Dato crítico a validar"] = ""
            wind_df["Dato crítico a validar"] = wind_df["Dato crítico a validar"].astype(str).where(
                wind_df["Dato crítico a validar"].astype(str).str.strip() != "",
                f"FP alimentado desde 09_Viento: {bridge_column}",
            )
            resource_override_rows = [
                {"Variable": "Velocidad media medición", "Valor": f"{bridge_speed:.2f}", "Unidad": "m/s", "Fuente requerida": f"09_Viento · {bridge_column}", "Uso": "Medición CSV", "Bloque": "CSV 09_Viento", "Valor numérico": bridge_speed},
                {"Variable": "Factor planta preliminar", "Valor": f"{bridge_fp:.1f}%", "Unidad": "%", "Fuente requerida": f"09_Viento · {bridge_column}", "Uso": "Modelo eólico", "Bloque": "CSV 09_Viento", "Valor numérico": bridge_fp},
                {"Variable": "Factor planta ficha", "Valor": f"{bridge_fp:.1f}%", "Unidad": "%", "Fuente requerida": f"09_Viento · {bridge_column}", "Uso": "Control", "Bloque": "CSV 09_Viento", "Valor numérico": bridge_fp},
                {"Variable": "Energía anual neta por turbina", "Valor": f"{bridge_energy:.0f}", "Unidad": "kWh/año", "Fuente requerida": f"09_Viento · {bridge_column}", "Uso": "Dimensionamiento", "Bloque": "CSV 09_Viento", "Valor numérico": bridge_energy},
                {"Variable": "Clasificación recurso", "Valor": bridge_class, "Unidad": "", "Fuente requerida": f"09_Viento · {bridge_column}", "Uso": "Riesgo técnico", "Bloque": "CSV 09_Viento", "Valor numérico": np.nan},
            ]
            resource_df = pd.concat([pd.DataFrame(resource_override_rows), resource_df], ignore_index=True)

    blue_1 = "#e0fbfc"
    blue_2 = "#98c1d9"
    blue_3 = "#293241"
    blue_4 = "#ee6c4d"
    blue_5 = "#3d5a80"
    blue_text = "#293241"
    turbine_order = ["VAWT 1 kW", "VAWT 3 kW", "VAWT 5 kW", "VAWT 10 kW", "VAWT 80 kW"]
    fallback_turbine_characteristics = pd.DataFrame(
        [
            ["VAWT 1 kW", 1.0, 12_182_800.0, 9.0, 2.65, 1.8, 4.77, 9.54],
            ["VAWT 3 kW", 3.0, 20_628_300.0, 10.0, 3.65, 2.3, 8.395, 16.79],
            ["VAWT 5 kW", 5.0, 32_305_700.0, 11.0, 4.5, 3.0, 13.5, 27.0],
            ["VAWT 10 kW", 10.0, 58_000_000.0, 14.0, 7.0, 5.0, 35.0, 70.0],
        ],
        columns=[
            "Alternativa",
            "Potencia unitaria kW",
            "CAPEX unitario $",
            "Altura total",
            "Altura rotor",
            "Diámetro rotor",
            "Área rotor",
            "Impacto superficial",
        ],
    )

    def normalize_turbine_characteristics(df: pd.DataFrame) -> pd.DataFrame:
        if df.empty:
            return fallback_turbine_characteristics.copy()
        normalized = df.copy()
        normalized.columns = [str(col).strip() for col in normalized.columns]
        if "Alternativa" not in normalized.columns:
            header_row = None
            for idx in range(min(6, len(normalized))):
                values = [str(value).strip().casefold() for value in normalized.iloc[idx].tolist()]
                if any("alternativa" in value for value in values):
                    header_row = idx
                    break
            if header_row is not None:
                normalized.columns = [str(value).strip() for value in normalized.iloc[header_row].tolist()]
                normalized = normalized.iloc[header_row + 1 :].reset_index(drop=True)
        rename_map = {}
        for col in normalized.columns:
            key = str(col).strip().casefold()
            if "alternativa" in key:
                rename_map[col] = "Alternativa"
            elif "potencia" in key and "kw" in key:
                rename_map[col] = "Potencia unitaria kW"
            elif "capex" in key:
                rename_map[col] = "CAPEX unitario $"
            elif "altura" in key and "total" in key:
                rename_map[col] = "Altura total"
            elif "altura" in key and "rotor" in key:
                rename_map[col] = "Altura rotor"
            elif ("diametro" in key or "diámetro" in key) and "rotor" in key:
                rename_map[col] = "Diámetro rotor"
            elif ("area" in key or "área" in key) and "rotor" in key:
                rename_map[col] = "Área rotor"
            elif "impacto" in key and "superficial" in key:
                rename_map[col] = "Impacto superficial"
        normalized = normalized.rename(columns=rename_map)
        required_cols = list(fallback_turbine_characteristics.columns)
        for col in required_cols:
            if col not in normalized.columns:
                normalized[col] = np.nan
        normalized = normalized[required_cols].copy()
        normalized["Alternativa"] = normalized["Alternativa"].astype(str).str.strip()
        normalized = normalized[normalized["Alternativa"].str.contains("VAWT", case=False, na=False)].copy()
        for col in required_cols[1:]:
            if col == "CAPEX unitario $":
                normalized[col] = normalized[col].map(
                    lambda value: parse_money_clp_robusto(str(value))
                    if parse_money_clp_robusto(str(value)) is not None
                    else parse_float_local(value, np.nan)
                )
            else:
                normalized[col] = normalized[col].map(lambda value: parse_float_local(value, np.nan))
        if normalized.empty:
            return fallback_turbine_characteristics.copy()
        fallback_by_alt = fallback_turbine_characteristics.set_index("Alternativa")
        for idx, row in normalized.iterrows():
            alt = str(row.get("Alternativa", "")).strip()
            if alt in fallback_by_alt.index:
                for col in required_cols[1:]:
                    value = pd.to_numeric(pd.Series([row.get(col)]), errors="coerce").iloc[0]
                    if pd.isna(value) or not np.isfinite(float(value)):
                        normalized.loc[idx, col] = fallback_by_alt.loc[alt, col]
        return normalized.reset_index(drop=True)

    def load_turbine_characteristics_table() -> pd.DataFrame:
        try:
            gid_map = load_google_pubhtml_sheet_gids(EVALUACION_TELECOM_PUBHTML_URL, refresh_nonce=data_refresh_nonce)
            characteristic_gid = None
            for sheet_name, gid in gid_map.items():
                normalized_name = str(sheet_name).strip().casefold()
                if "caracter" in normalized_name or "turbina" in normalized_name:
                    characteristic_gid = gid
                    break
            if characteristic_gid:
                characteristic_url = f"{EVALUACION_TELECOM_PUB_BASE_URL}?gid={characteristic_gid}&single=true&output=csv"
                return normalize_turbine_characteristics(
                    read_remote_csv(characteristic_url, refresh_nonce=data_refresh_nonce, dtype=str).fillna("")
                )
        except Exception:
            pass
        return fallback_turbine_characteristics.copy()

    turbine_characteristics_df = load_turbine_characteristics_table()

    def current_wind_height_profile() -> pd.DataFrame:
        csv_outputs = st.session_state.get("telecom_09_viento_outputs", {}) or {}
        profile = pd.DataFrame(csv_outputs.get("perfil_alturas", []))
        if profile.empty:
            manual_outputs = st.session_state.get("telecom_09_manual_wind_outputs", {}) or {}
            if bool(manual_outputs.get("enabled", False)):
                profile = pd.DataFrame(manual_outputs.get("perfil_alturas", []))
        if profile.empty:
            return pd.DataFrame()
        for col in ["Altura m", "FP neto", "Velocidad media", "Energía anual neta kWh", "Horas equivalentes", "Weibull k", "Weibull c"]:
            if col in profile.columns:
                profile[col] = pd.to_numeric(profile[col], errors="coerce")
        if not {"Altura m", "FP neto"}.issubset(profile.columns):
            return pd.DataFrame()
        return profile.dropna(subset=["Altura m", "FP neto"]).sort_values("Altura m").reset_index(drop=True)

    def interpolate_wind_profile_value(profile: pd.DataFrame, target_height: float, value_col: str) -> tuple[float, str]:
        if profile.empty or value_col not in profile.columns or not np.isfinite(float(target_height)):
            return np.nan, ""
        heights = profile["Altura m"].to_numpy(dtype=float)
        values = pd.to_numeric(profile[value_col], errors="coerce").to_numpy(dtype=float)
        valid = np.isfinite(heights) & np.isfinite(values)
        heights = heights[valid]
        values = values[valid]
        if len(heights) == 0:
            return np.nan, ""
        if len(heights) == 1:
            nearest_col = str(profile.iloc[0].get("Columna", ""))
            return float(values[0]), nearest_col
        interpolated = float(np.interp(float(target_height), heights, values, left=values[0], right=values[-1]))
        nearest_height = heights[int(np.argmin(np.abs(heights - float(target_height))))]
        nearest_rows = profile[np.isclose(profile["Altura m"], nearest_height)]
        nearest_col = str(nearest_rows.iloc[0].get("Columna", "")) if not nearest_rows.empty else ""
        return interpolated, nearest_col

    def years_label(value) -> str:
        if pd.isna(value) or not np.isfinite(float(value)):
            return "N/A"
        months_total = max(1, int(round(float(value) * 12)))
        years = months_total // 12
        months = months_total % 12
        if years == 0:
            return f"{months} meses"
        if months == 0:
            return f"{years} año" if years == 1 else f"{years} años"
        return f"{years} años {months} meses"

