    st.markdown(
        f"""
        <div class="telecom-hero">
          <p class="telecom-k">Propuesta técnica · Generación eólica telecom</p>
          <h2 class="telecom-t">Propuesta técnica de generación eólica para torres telecom</h2>
          <p class="telecom-s">Modelo ejecutivo para presentar una solución de generación eólica aplicada a PoP telecom. Ordena el caso técnico-comercial por sitio seleccionado, recurso eólico disponible, producción esperada, recomendación de turbina, CAPEX instalado y plan de ejecución.</p>
        </div>
        """,
        unsafe_allow_html=True,
    )
    # En la version cliente no mostramos alertas tecnicas de fallback:
    # la app conserva datos base para continuidad si Google Sheets responde lento.

    def render_active_pop_note(context_label: str = "esta pestaña") -> None:
        active_pop = str(st.session_state.get("telecom_client_selected_pop", "") or "").strip()
        if active_pop:
            st.markdown(
                f"""
                <div class="telecom-note">
                  <b>PoP activo:</b> {html.escape(active_pop)} · selección definida en
                  <b>01 Perfil del Sitio</b>. Los cálculos y visualizaciones de {html.escape(context_label)}
                  usan esta selección como caso vigente.
                </div>
                """,
                unsafe_allow_html=True,
            )
        else:
            st.info("Selecciona un PoP en 01 Perfil del Sitio para fijar el caso técnico de generación eólica.")

    def render_wind_csv_analysis_tab() -> None:
        def _clean_numeric_series(series: pd.Series) -> pd.Series:
            if pd.api.types.is_numeric_dtype(series):
                return pd.to_numeric(series, errors="coerce")
            cleaned = (
                series.astype(str)
                .str.replace("\u00a0", "", regex=False)
                .str.replace(" ", "", regex=False)
                .str.replace(",", ".", regex=False)
            )
            return pd.to_numeric(cleaned, errors="coerce")

        def _datetime_candidate_quality(series: pd.Series) -> tuple[pd.Series, float, float]:
            parsed = pd.to_datetime(series, errors="coerce")
            valid_ratio = float(parsed.notna().mean() or 0.0)
            valid = parsed.dropna()
            if len(valid) >= 2:
                span_hours = float((valid.max() - valid.min()).total_seconds() / 3600.0)
            else:
                span_hours = 0.0
            return parsed, valid_ratio, span_hours

        def _detect_best_datetime_column(df: pd.DataFrame, min_ratio: float = 0.70) -> tuple[str | None, pd.Series | None, float, float]:
            if df.empty:
                return None, None, 0.0, 0.0
            ordered_cols = list(df.columns)
            first_col = ordered_cols[0]
            first_name = str(first_col).strip().casefold()
            first_is_unnamed = first_name.startswith("unnamed") or first_name in {"", "nan", "none"}
            candidates = []
            for col in ordered_cols:
                name = str(col).strip().casefold()
                is_first = col == first_col
                is_named_as_date = any(token in name for token in ["fecha", "date", "hora", "time", "timestamp", "datetime"])
                is_unnamed = name.startswith("unnamed") or name in {"", "nan", "none"}
                if pd.api.types.is_numeric_dtype(df[col]) and not is_named_as_date:
                    continue
                parsed, valid_ratio, span_hours = _datetime_candidate_quality(df[col])
                if valid_ratio < min_ratio:
                    continue
                if len(df) > 24 and span_hours < 12:
                    continue
                priority = 0
                if is_first and first_is_unnamed:
                    priority = 3
                elif is_named_as_date:
                    priority = 2
                elif is_unnamed:
                    priority = 1
                candidates.append((priority, valid_ratio, span_hours, col, parsed))
            if not candidates:
                return None, None, 0.0, 0.0
            priority, valid_ratio, span_hours, col, parsed = sorted(candidates, key=lambda item: (item[0], item[1], item[2]), reverse=True)[0]
            return col, parsed, float(valid_ratio), float(span_hours)

        def _detect_datetime_columns(df: pd.DataFrame) -> list[str]:
            candidates = []
            for col in df.columns:
                name = str(col).strip().casefold()
                is_named_as_date = any(token in name for token in ["fecha", "date", "hora", "time", "timestamp", "datetime"])
                if pd.api.types.is_numeric_dtype(df[col]) and not is_named_as_date:
                    continue
                parsed, valid_ratio, span_hours = _datetime_candidate_quality(df[col])
                if valid_ratio >= 0.70 and (len(df) <= 24 or span_hours >= 12):
                    candidates.append((col, valid_ratio, span_hours))
            return [col for col, _, _ in sorted(candidates, key=lambda item: (item[1], item[2]), reverse=True)]

        def _normalize_csv_columns(df: pd.DataFrame) -> tuple[pd.DataFrame, dict]:
            if df.empty:
                return df, {}
            renamed = df.copy()
            detected_col, parsed, valid_ratio, span_hours = _detect_best_datetime_column(renamed)
            detection_meta = {
                "detected_col_original": detected_col,
                "valid_ratio": valid_ratio,
                "span_hours": span_hours,
                "message": "",
            }
            if detected_col is not None:
                renamed["Fecha/hora"] = parsed
                if detected_col != "Fecha/hora":
                    renamed = renamed.drop(columns=[detected_col])
                original_name = str(detected_col).strip().casefold()
                first_name = str(df.columns[0]).strip().casefold()
                if detected_col == df.columns[0] and (first_name.startswith("unnamed") or first_name in {"", "nan", "none"}):
                    detection_meta["message"] = "Fecha/hora detectada correctamente desde la primera columna del CSV."
                else:
                    detection_meta["message"] = f"Fecha/hora detectada correctamente desde `{detected_col}`."

            wind_renames = {}
            used_names = {str(col).strip() for col in renamed.columns}
            for col in renamed.columns:
                if col == "Fecha/hora":
                    continue
                col_text = str(col).strip()
                try:
                    height = float(col_text.replace(",", "."))
                except ValueError:
                    continue
                numeric = _clean_numeric_series(renamed[col])
                if float(numeric.notna().mean() or 0.0) < 0.50:
                    continue
                height_label = f"{height:g}".replace(",", ".")
                new_name = f"Viento_{height_label}m"
                suffix = 2
                unique_name = new_name
                while unique_name in used_names:
                    unique_name = f"{new_name}_{suffix}"
                    suffix += 1
                wind_renames[col] = unique_name
                used_names.add(unique_name)
            if wind_renames:
                renamed = renamed.rename(columns=wind_renames)
            return renamed, detection_meta

        def _datetime_quality_summary(datetimes: pd.Series) -> dict:
            clean_dt = pd.to_datetime(datetimes, errors="coerce").dropna().sort_values()
            unique_dt = clean_dt.drop_duplicates()
            if unique_dt.empty:
                return {
                    "Inicio": "Sin fecha",
                    "Término": "Sin fecha",
                    "Registros con fecha": 0,
                    "Horas esperadas": 0,
                    "Horas faltantes": 0,
                    "Frecuencia": "No disponible",
                }
            start = unique_dt.iloc[0]
            end = unique_dt.iloc[-1]
            expected_hours = int(((end - start).total_seconds() / 3600.0) + 1) if end >= start else int(len(unique_dt))
            missing_hours = max(0, expected_hours - int(len(unique_dt)))
            diffs = unique_dt.diff().dropna()
            hourly_ratio = float((diffs == pd.Timedelta(hours=1)).mean() or 0.0) if not diffs.empty else 1.0
            return {
                "Inicio": start.strftime("%Y-%m-%d %H:%M"),
                "Término": end.strftime("%Y-%m-%d %H:%M"),
                "Registros con fecha": int(len(clean_dt)),
                "Horas esperadas": int(expected_hours),
                "Horas faltantes": int(missing_hours),
                "Frecuencia": "Horaria" if hourly_ratio >= 0.80 else "Irregular",
            }

        def _detect_wind_columns(df: pd.DataFrame, date_cols: list[str]) -> list[str]:
            wind_cols = []
            for col in df.columns:
                if col in date_cols:
                    continue
                numeric = _clean_numeric_series(df[col])
                valid_ratio = float(numeric.notna().mean() or 0.0)
                if valid_ratio < 0.50:
                    continue
                positive_ratio = float((numeric > 0).mean() or 0.0)
                name = str(col).casefold()
                named_as_wind = any(token in name for token in ["viento", "wind", "vel", "ws", "m/s", "ms", "speed"])
                plausible_speed = numeric.quantile(0.95) <= 80 and numeric.quantile(0.50) <= 40
                if named_as_wind or (positive_ratio >= 0.40 and plausible_speed):
                    wind_cols.append(col)
            return wind_cols

        def _weibull_params(values: pd.Series) -> tuple[float, float]:
            clean = pd.to_numeric(values, errors="coerce").dropna()
            clean = clean[clean > 0]
            if clean.empty:
                return np.nan, np.nan
            mean = float(clean.mean())
            std = float(clean.std(ddof=1) or 0.0)
            if mean <= 0 or std <= 0:
                return np.nan, np.nan
            cv = std / mean
            k = max(0.35, min(12.0, cv ** -1.086))
            c = mean / math.gamma(1.0 + 1.0 / k)
            return float(k), float(c)

        def _weibull_pdf(x: np.ndarray, k: float, c: float) -> np.ndarray:
            if not np.isfinite(k) or not np.isfinite(c) or k <= 0 or c <= 0:
                return np.zeros_like(x, dtype=float)
            x_safe = np.clip(x, 0, None)
            return (k / c) * ((x_safe / c) ** (k - 1.0)) * np.exp(-((x_safe / c) ** k))

        cp_10kw_default_url = "https://docs.google.com/spreadsheets/d/e/2PACX-1vRGia7ve1SPnRIue5iqiYB4l9BapwtJozB3zM93hHzm4y6MjTWPR-G_GGkmTRkPVxvnz3dtCU8XcX3B/pub?gid=774855027&single=true&output=csv"

        def _parse_curve_number(value, default: float = np.nan) -> float:
            text = str(value).strip()
            if not text or text.casefold() in {"nan", "none"}:
                return default
            text = text.replace("\u00a0", "").replace(" ", "")
            if "," in text:
                text = text.replace(".", "").replace(",", ".")
            elif re.fullmatch(r"-?\d{1,3}(?:\.\d{3})+", text):
                text = text.replace(".", "")
            return parse_float_local(text, default)

        def _load_power_curve_from_url(url: str) -> pd.DataFrame:
            if not str(url or "").strip():
                return pd.DataFrame()
            try:
                curve_raw = read_remote_csv(str(url).strip(), refresh_nonce=data_refresh_nonce, dtype=str).fillna("")
            except Exception:
                return pd.DataFrame()
            if curve_raw.shape[1] < 2:
                return pd.DataFrame()
            curve = curve_raw.iloc[:, :2].copy()
            curve.columns = ["Velocidad m/s", "Potencia W"]
            curve["Velocidad m/s"] = curve["Velocidad m/s"].map(_parse_curve_number)
            curve["Potencia W"] = curve["Potencia W"].map(_parse_curve_number)
            curve = curve.dropna(subset=["Velocidad m/s", "Potencia W"])
            curve = curve[(curve["Velocidad m/s"] >= 0) & (curve["Potencia W"] >= 0)].copy()
            if curve.empty:
                return pd.DataFrame()
            curve["Potencia kW"] = curve["Potencia W"] / 1000.0
            return curve.sort_values("Velocidad m/s").drop_duplicates("Velocidad m/s", keep="last").reset_index(drop=True)

        def _power_curve(speed: pd.Series, rated_kw: float, cut_in: float, rated_speed: float, cut_out: float) -> pd.Series:
            v = pd.to_numeric(speed, errors="coerce").fillna(0.0).clip(lower=0.0)
            power = pd.Series(np.zeros(len(v)), index=v.index, dtype=float)
            ramp_mask = (v >= cut_in) & (v < rated_speed)
            if rated_speed > cut_in:
                numerator = (v[ramp_mask] ** 3) - (cut_in ** 3)
                denominator = (rated_speed ** 3) - (cut_in ** 3)
                power.loc[ramp_mask] = rated_kw * (numerator / denominator).clip(lower=0.0, upper=1.0)
            rated_mask = (v >= rated_speed) & (v <= cut_out)
            power.loc[rated_mask] = rated_kw
            return power.clip(lower=0.0, upper=max(rated_kw, 0.0))

        def _power_curve_from_table(speed: pd.Series, curve_df: pd.DataFrame, cut_in: float, cut_out: float) -> pd.Series:
            v = pd.to_numeric(speed, errors="coerce").fillna(0.0).clip(lower=0.0)
            if curve_df.empty or not {"Velocidad m/s", "Potencia kW"}.issubset(curve_df.columns):
                return pd.Series(np.zeros(len(v)), index=v.index, dtype=float)
            curve_speed = pd.to_numeric(curve_df["Velocidad m/s"], errors="coerce").to_numpy(dtype=float)
            curve_power = pd.to_numeric(curve_df["Potencia kW"], errors="coerce").to_numpy(dtype=float)
            valid = np.isfinite(curve_speed) & np.isfinite(curve_power)
            curve_speed = curve_speed[valid]
            curve_power = curve_power[valid]
            if len(curve_speed) == 0:
                return pd.Series(np.zeros(len(v)), index=v.index, dtype=float)
            power_values = np.interp(v.to_numpy(dtype=float), curve_speed, curve_power, left=0.0, right=float(curve_power[-1]))
            power = pd.Series(power_values, index=v.index, dtype=float)
            power.loc[(v < cut_in) | (v > cut_out)] = 0.0
            return power.clip(lower=0.0)

        def _effective_curve_rated_kw(rated_kw: float, curve_df: pd.DataFrame, use_table_curve: bool) -> float:
            if use_table_curve and not curve_df.empty and "Potencia kW" in curve_df.columns:
                max_curve = pd.to_numeric(curve_df["Potencia kW"], errors="coerce").dropna()
                if not max_curve.empty and float(max_curve.max()) > 0:
                    return float(max_curve.max())
            return float(rated_kw)

        def _resource_label(mean_speed: float, cf_net: float) -> str:
            if cf_net >= 0.35 or mean_speed >= 7.0:
                return "Muy atractivo"
            if cf_net >= 0.25 or mean_speed >= 5.5:
                return "Útil"
            if cf_net >= 0.15 or mean_speed >= 4.0:
                return "Inicial"
            return "Bajo"

        def _analyze_column(
            df: pd.DataFrame,
            speed_col: str,
            dt_col: str | None,
            outlier_limit: float,
            rated_kw: float,
            cut_in: float,
            rated_speed: float,
            cut_out: float,
            electrical_losses: float,
            availability: float,
            additional_losses: float,
            power_curve_df: pd.DataFrame | None = None,
            use_table_curve: bool = False,
        ) -> dict:
            speed_raw = _clean_numeric_series(df[speed_col])
            valid_mask = speed_raw.notna() & (speed_raw > 0) & (speed_raw <= outlier_limit)
            clean_speed = speed_raw.where(valid_mask)
            power_curve_df = power_curve_df if isinstance(power_curve_df, pd.DataFrame) else pd.DataFrame()
            rated_for_cf = _effective_curve_rated_kw(rated_kw, power_curve_df, use_table_curve)
            if use_table_curve and not power_curve_df.empty:
                power_bruta = _power_curve_from_table(clean_speed, power_curve_df, cut_in, cut_out)
            else:
                power_bruta = _power_curve(clean_speed, rated_kw, cut_in, rated_speed, cut_out)
            net_multiplier = max(0.0, (1.0 - electrical_losses / 100.0) * (availability / 100.0) * (1.0 - additional_losses / 100.0))
            power_neta = power_bruta * net_multiplier
            annual_gross = float(power_bruta.mean(skipna=True) * 8760.0) if power_bruta.notna().any() else 0.0
            annual_net = float(power_neta.mean(skipna=True) * 8760.0) if power_neta.notna().any() else 0.0
            cf_gross = annual_gross / (rated_for_cf * 8760.0) if rated_for_cf > 0 else np.nan
            cf_net = annual_net / (rated_for_cf * 8760.0) if rated_for_cf > 0 else np.nan
            k, c = _weibull_params(clean_speed)
            valid_count = int(valid_mask.sum())
            total_count = int(len(speed_raw))
            return {
                "Columna": str(speed_col),
                "Registros": total_count,
                "Válidos": valid_count,
                "% válido": valid_count / total_count * 100.0 if total_count else 0.0,
                "Nulos": int(speed_raw.isna().sum()),
                "Ceros/negativos": int(((speed_raw <= 0) & speed_raw.notna()).sum()),
                "Outliers": int((speed_raw > outlier_limit).sum()),
                "Velocidad media": float(clean_speed.mean(skipna=True) or 0.0),
                "Mediana": float(clean_speed.median(skipna=True) or 0.0),
                "Mínimo": float(clean_speed.min(skipna=True) or 0.0),
                "Máximo": float(clean_speed.max(skipna=True) or 0.0),
                "Desv. estándar": float(clean_speed.std(skipna=True) or 0.0),
                "P10": float(clean_speed.quantile(.10) or 0.0),
                "P25": float(clean_speed.quantile(.25) or 0.0),
                "P50": float(clean_speed.quantile(.50) or 0.0),
                "P75": float(clean_speed.quantile(.75) or 0.0),
                "P90": float(clean_speed.quantile(.90) or 0.0),
                "CV": float((clean_speed.std(skipna=True) / clean_speed.mean(skipna=True)) if clean_speed.mean(skipna=True) else np.nan),
                "Weibull k": k,
                "Weibull c": c,
                "Energía anual bruta kWh": annual_gross,
                "Energía anual neta kWh": annual_net,
                "FP bruto": cf_gross * 100.0 if np.isfinite(cf_gross) else np.nan,
                "FP neto": cf_net * 100.0 if np.isfinite(cf_net) else np.nan,
                "Horas equivalentes": annual_net / rated_for_cf if rated_for_cf > 0 else np.nan,
                "Potencia referencia kW": rated_for_cf,
                "Fuente curva potencia": "Curva publicada 10 kW" if use_table_curve and not power_curve_df.empty else "Curva cúbica editable",
                "Clasificación": _resource_label(float(clean_speed.mean(skipna=True) or 0.0), float(cf_net or 0.0)),
                "_speed": clean_speed,
                "_power_bruta": power_bruta,
                "_power_neta": power_neta,
            }

