        default_mix_diesel = selected_site_numeric(["Mix Electrógeno", "Mix Electrogeno", "Diésel %", "Diesel %"], default_mix_diesel)
        default_mix_bess = selected_bess_mix_value(default_mix_bess)
        default_surplus_price = 0.0
