    if not st.session_state.get("sim6_zero_defaults_applied"):
        st.session_state["sim6_safety_margin"] = 0.0
        st.session_state["sim6_surplus_price"] = 0.0
        st.session_state["sim6_zero_defaults_applied"] = True

    with st.expander("Parámetros de simulación técnica, económica y CAPEX", expanded=False):
        st.markdown(
            '<div class="sim6-input-note">El CAPEX unitario de turbina se toma desde la pestaña CAPEX como CAPEX instalado unitario. No se edita en esta vista para mantener consistencia entre recomendación, suministro e instalación.</div>',
            unsafe_allow_html=True,
        )
        with st.container(border=True):
            st.markdown("##### Demanda y continuidad")
            d1, d2, d3, d4 = st.columns(4)
            with d1:
                monthly_consumption = st.number_input("Consumo mensual sitio (kWh/mes)", min_value=100.0, value=float(default_monthly_consumption), step=50.0, key="sim6_monthly_consumption")
            with d2:
                target_coverage = st.slider("Cobertura objetivo (%)", min_value=20.0, max_value=160.0, value=float(max(20.0, min(160.0, default_target_coverage))), step=5.0, key="sim6_target_coverage")
            with d3:
                safety_margin = st.slider("Margen de seguridad (%)", min_value=0.0, max_value=40.0, value=0.0, step=2.5, key="sim6_safety_margin")
            with d4:
                project_life = st.number_input("Vida útil análisis (años)", min_value=5, max_value=30, value=int(default_project_life), step=1, key="sim6_project_life")

        with st.container(border=True):
            st.markdown("##### Recurso eólico y operación")
            e1, e2, e3, e4, e5 = st.columns(5)
            with e1:
                plant_factor_value = float(max(10.0, min(60.0, default_plant_factor)))
                plant_factor = st.slider(
                    "Factor planta base (%)",
                    min_value=10.0,
                    max_value=60.0,
                    value=plant_factor_value,
                    step=0.5,
                    key="sim6_plant_factor_locked" if wind_csv_bridge_active else "sim6_plant_factor",
                    disabled=wind_csv_bridge_active,
                    help="Bloqueado porque existe data activa desde 02 Recurso de Viento." if wind_csv_bridge_active else None,
                )
            with e2:
                availability = st.slider("Disponibilidad (%)", min_value=70.0, max_value=100.0, value=float(max(70.0, min(100.0, default_availability))), step=1.0, key="sim6_availability")
            with e3:
                electrical_losses = st.slider("Pérdidas eléctricas (%)", min_value=0.0, max_value=25.0, value=float(max(0.0, min(25.0, default_electrical_losses))), step=0.5, key="sim6_electrical_losses")
            with e4:
                additional_losses = st.slider("Pérdidas adicionales (%)", min_value=0.0, max_value=25.0, value=float(max(0.0, min(25.0, default_additional_losses))), step=0.5, key="sim6_additional_losses")
            with e5:
                degradation = st.slider("Degradación anual (%)", min_value=0.0, max_value=3.0, value=0.5, step=0.1, key="sim6_degradation")

        with st.container(border=True):
            st.markdown("##### Economía energética")
            c1, c2, c3, c4 = st.columns(4)
            with c1:
                grid_cost = st.number_input("Costo red (CLP/kWh)", min_value=0.0, value=float(default_grid_cost), step=10.0, key="sim6_grid_cost")
                mix_grid = st.slider("Mix red (%)", min_value=0.0, max_value=100.0, value=float(max(0.0, min(100.0, default_mix_grid))), step=5.0, key="sim6_mix_grid")
            with c2:
                diesel_cost = st.number_input("Costo electrógeno (CLP/kWh)", min_value=0.0, value=float(default_diesel_cost), step=25.0, key="sim6_diesel_cost")
                mix_diesel = st.slider("Mix electrógeno (%)", min_value=0.0, max_value=100.0, value=float(max(0.0, min(100.0, default_mix_diesel))), step=5.0, key="sim6_mix_diesel")
            with c3:
                bess_cost = st.number_input("Costo FV/BESS ref. (CLP/kWh)", min_value=0.0, value=float(default_bess_cost), step=10.0, key="sim6_bess_cost")
                mix_bess = st.slider("Mix FV/BESS (%)", min_value=0.0, max_value=100.0, value=float(max(0.0, min(100.0, default_mix_bess))), step=5.0, key="sim6_mix_bess")
            with c4:
                surplus_price = st.number_input("Monetización excedente (CLP/kWh)", min_value=0.0, value=float(default_surplus_price), step=10.0, key="sim6_surplus_price")
                surplus_factor = st.slider("Factor valorización excedente", min_value=0.0, max_value=2.0, value=float(max(0.0, min(2.0, default_surplus_factor))), step=0.05, key="sim6_surplus_factor")

        with st.container(border=True):
            st.markdown("##### CAPEX, O&M e impacto")
            k1, k2, k3, k4, k5 = st.columns(5)
            with k1:
                capex_installed_active = bool(capex_unit_source_by_model)
                bos_pct_input = st.slider(
                    "BOS / instalación (%)",
                    min_value=0.0,
                    max_value=80.0,
                    value=0.0 if capex_installed_active else float(max(0.0, min(80.0, default_bos_pct))),
                    step=2.5,
                    key="sim6_bos_pct_installed_locked" if capex_installed_active else "sim6_bos_pct",
                    disabled=capex_installed_active,
                    help=(
                        "Desactivado: el CAPEX instalado unitario ya incluye suministro e instalación desde la pestaña CAPEX."
                        if capex_installed_active
                        else None
                    ),
                )
                bos_pct = 0.0 if capex_installed_active else bos_pct_input
            with k2:
                om_pct = st.slider("O&M anual sobre CAPEX (%)", min_value=0.0, max_value=12.0, value=float(max(0.0, min(12.0, default_om_pct))), step=0.25, key="sim6_om_pct")
            with k3:
                diesel_l_kwh = st.number_input("Consumo diésel evitado (L/kWh)", min_value=0.0, value=float(default_diesel_l_kwh), step=0.01, key="sim6_diesel_l_kwh")
            with k4:
                co2_kg_l = st.number_input("Factor emisión diésel (kgCO2/L)", min_value=0.0, value=float(default_co2_kg_l), step=0.01, key="sim6_co2_kg_l")
            with k5:
                surface_per_kw = st.number_input("Impacto superficial (m²/kW)", min_value=0.0, value=float(default_surface_per_kw), step=0.5, key="sim6_surface_per_kw")

            unit_capex = {}
            capex_rows = []
            for name in turbine_order:
                capex_default = float(
                    default_unit_capex[name]
                    if name in default_unit_capex
                    else wind_default(name, "CAPEX unitario $", default_unit_capex.get(name, 0.0))
                )
                unit_capex[name] = capex_default
                capex_rows.append(
                    {
                        "Turbina": name,
                        "CAPEX instalado unitario": format_clp(capex_default),
                        "Fuente": capex_unit_source_by_model.get(name, "Fallback modelo técnico"),
                    }
                )
            st.dataframe(
                pd.DataFrame(capex_rows),
                hide_index=True,
                use_container_width=True,
                height=min(182, 42 + 36 * max(1, len(capex_rows))),
            )

    mix_grid_active = mix_grid if mix_grid > 0.0001 else 0.0
    mix_diesel_active = mix_diesel if mix_diesel > 0.0001 else 0.0
    mix_bess_active = mix_bess if mix_bess > 0.0001 else 0.0
    grid_cost_active = grid_cost if mix_grid_active > 0 else 0.0
    diesel_cost_active = diesel_cost if mix_diesel_active > 0 else 0.0
    bess_cost_active = bess_cost if mix_bess_active > 0 else 0.0
    mix_total = mix_grid_active + mix_diesel_active + mix_bess_active
    if mix_total <= 0:
        grid_share = diesel_share = bess_share = 0.0
        weighted_cost = 0.0
    else:
        grid_share = mix_grid_active / mix_total
        diesel_share = mix_diesel_active / mix_total
        bess_share = mix_bess_active / mix_total
        weighted_cost = grid_share * grid_cost_active + diesel_share * diesel_cost_active + bess_share * bess_cost_active
    original_mix_total = mix_grid + mix_diesel + mix_bess
    if abs(original_mix_total - 100.0) > 0.01:
        st.caption(f"Mix ingresado suma {original_mix_total:.0f}%; el cálculo lo normaliza internamente a 100%.")

    net_factor = max(0.0, (availability / 100.0) * (1.0 - electrical_losses / 100.0) * (1.0 - additional_losses / 100.0))
    effective_pf = plant_factor / 100.0 * net_factor
    wind_profile = pd.DataFrame(st.session_state.get("telecom_09_viento_outputs", {}).get("perfil_alturas", []))
    wind_monthly_profile = pd.DataFrame(st.session_state.get("telecom_09_viento_outputs", {}).get("perfil_mensual_alturas", []))
    if not wind_profile.empty:
        for col in ["Altura m", "FP neto", "Velocidad media", "Energía anual neta kWh", "Horas equivalentes", "Weibull k", "Weibull c"]:
            if col in wind_profile.columns:
                wind_profile[col] = pd.to_numeric(wind_profile[col], errors="coerce")
        wind_profile = wind_profile.dropna(subset=["Altura m", "FP neto"]).sort_values("Altura m")
    if not wind_monthly_profile.empty:
        for col in ["Altura m", "Mes", "Energía mensual neta kWh por turbina"]:
            if col in wind_monthly_profile.columns:
                wind_monthly_profile[col] = pd.to_numeric(wind_monthly_profile[col], errors="coerce")
        wind_monthly_profile = wind_monthly_profile.dropna(subset=["Altura m", "Mes", "Energía mensual neta kWh por turbina"]).sort_values(["Mes", "Altura m"])

    curve_summary_df = pd.DataFrame(
        st.session_state.get("telecom_03_curve_active_summary_df", [])
        or st.session_state.get("telecom_03_curve_summary_df", [])
    )
    if not curve_summary_df.empty:
        for col in [
            "Pn nominal kW", "Altura total turbina m", "Altura barrida rotor m", "Altura torre m",
            "Altura efectiva viento m", "Velocidad interpolada m/s", "Potencia media kW",
            "FP curva %", "Energía anual kWh", "Torque operativo Nm",
        ]:
            if col in curve_summary_df.columns:
                curve_summary_df[col] = pd.to_numeric(curve_summary_df[col], errors="coerce")
    curve_summary_by_model = {
        str(row.get("Modelo", "")).strip(): row
        for _, row in curve_summary_df.iterrows()
        if str(row.get("Modelo", "")).strip()
    }

    def wind_profile_for_turbine(name: str) -> dict:
        char_row = characteristics_by_alt.get(name)
        height_total = np.nan
        rotor_height = np.nan
        rotor_diameter = np.nan
        rotor_area = np.nan
        impact_surface = np.nan
        if char_row is not None:
            height_total = float(char_row.get("Altura total", np.nan))
            rotor_height = float(char_row.get("Altura rotor", np.nan))
            rotor_diameter = float(char_row.get("Diámetro rotor", np.nan))
            rotor_area = float(char_row.get("Área rotor", np.nan))
            impact_surface = float(char_row.get("Impacto superficial", np.nan))
        curve_row = curve_summary_by_model.get(name)
        if curve_row is not None:
            curve_height_total = float(curve_row.get("Altura total turbina m", np.nan))
            curve_rotor_height = float(curve_row.get("Altura barrida rotor m", np.nan))
            curve_pf = float(curve_row.get("FP curva %", np.nan)) / 100.0
            curve_annual = float(curve_row.get("Energía anual kWh", np.nan))
            if np.isfinite(curve_height_total):
                height_total = curve_height_total
            if np.isfinite(curve_rotor_height):
                rotor_height = curve_rotor_height
            if np.isfinite(curve_pf) and curve_pf > 0:
                return {
                    "height_total": height_total,
                    "rotor_height": rotor_height,
                    "rotor_diameter": rotor_diameter,
                    "rotor_area": rotor_area,
                    "impact_surface": impact_surface,
                    "pf": max(0.0, curve_pf),
                    "source": "03 Producción por Turbina · curva GREEF + viento interpolado",
                    "wind_col": str(curve_row.get("Fuente medición", "")),
                    "annual_kwh_per_turbine": curve_annual if np.isfinite(curve_annual) and curve_annual > 0 else np.nan,
                    "monthly_kwh_per_turbine": curve_annual / 12.0 if np.isfinite(curve_annual) and curve_annual > 0 else np.nan,
                }
        if wind_profile.empty or not np.isfinite(height_total):
            return {
                "height_total": height_total,
                "rotor_height": rotor_height,
                "rotor_diameter": rotor_diameter,
                "rotor_area": rotor_area,
                "impact_surface": impact_surface,
                "pf": effective_pf,
                "source": "Input base",
                "wind_col": "",
                "annual_kwh_per_turbine": np.nan,
                "monthly_kwh_per_turbine": np.nan,
            }
        heights = wind_profile["Altura m"].to_numpy(dtype=float)
        fps = (wind_profile["FP neto"].to_numpy(dtype=float) / 100.0)
        valid = np.isfinite(heights) & np.isfinite(fps)
        heights = heights[valid]
        fps = fps[valid]
        if len(heights) == 0:
            pf_value = effective_pf
            wind_col = ""
        elif len(heights) == 1:
            pf_value = float(fps[0])
            wind_col = str(wind_profile.iloc[0].get("Columna", ""))
        else:
            pf_value = float(np.interp(height_total, heights, fps, left=fps[0], right=fps[-1]))
            nearest_idx = int(np.argmin(np.abs(heights - height_total)))
            wind_col = str(wind_profile.iloc[nearest_idx].get("Columna", ""))
        return {
            "height_total": height_total,
            "rotor_height": rotor_height,
            "rotor_diameter": rotor_diameter,
            "rotor_area": rotor_area,
            "impact_surface": impact_surface,
            "pf": max(0.0, pf_value),
            "source": "09_Viento por altura",
            "wind_col": wind_col,
            "annual_kwh_per_turbine": np.nan,
            "monthly_kwh_per_turbine": np.nan,
        }

    required_monthly = monthly_consumption * (target_coverage + safety_margin) / 100.0
    rows = []
    for name in turbine_order:
        kw = turbine_kw[name]
        wind_match = wind_profile_for_turbine(name)
        pf_for_turbine = float(wind_match["pf"])
        curve_monthly_kwh = float(wind_match.get("monthly_kwh_per_turbine", np.nan))
        gen_month_turbine = curve_monthly_kwh if np.isfinite(curve_monthly_kwh) and curve_monthly_kwh > 0 else kw * 8760.0 * pf_for_turbine / 12.0
        turbines = int(max(1, math.ceil(required_monthly / gen_month_turbine))) if gen_month_turbine > 0 else 0
        installed_kw = turbines * kw
        gen_month_total = gen_month_turbine * turbines
        gen_year_total = gen_month_total * 12.0
        useful_monthly = min(gen_month_total, monthly_consumption)
        surplus_monthly = max(gen_month_total - monthly_consumption, 0.0)
        coverage_real = gen_month_total / monthly_consumption * 100.0 if monthly_consumption > 0 else 0.0
        useful_coverage = useful_monthly / monthly_consumption * 100.0 if monthly_consumption > 0 else 0.0
        capex_turbines = turbines * unit_capex[name]
        capex_uses_installed_unit = name in capex_unit_source_by_model
        capex_total = capex_turbines if capex_uses_installed_unit else capex_turbines * (1.0 + bos_pct / 100.0)
        capex_source = capex_unit_source_by_model.get(name, "CAPEX unitario input técnico + BOS")
        om_annual = capex_total * om_pct / 100.0
        gross_saving = useful_monthly * 12.0 * weighted_cost
        surplus_income = surplus_monthly * 12.0 * surplus_price * surplus_factor
        benefit_net = max(gross_saving + surplus_income - om_annual, 0.0)
        payback = capex_total / benefit_net if benefit_net > 0 else np.nan
        lcoe = ((capex_total / project_life) + om_annual) / gen_year_total if gen_year_total > 0 and project_life > 0 else np.nan
        diesel_avoided = useful_monthly * 12.0 * diesel_share * diesel_l_kwh
        co2_avoided = diesel_avoided * co2_kg_l / 1000.0
        benefit_20 = sum(benefit_net * ((1.0 - degradation / 100.0) ** year) for year in range(int(project_life))) - capex_total
        if np.isfinite(float(wind_match.get("impact_surface", np.nan))):
            surface = turbines * float(wind_match["impact_surface"])
        else:
            surface = installed_kw * surface_per_kw
        rows.append(
            {
                "Alternativa": name,
                "Potencia unitaria kW": kw,
                "Altura total m": wind_match["height_total"],
                "Altura rotor m": wind_match["rotor_height"],
                "FP aplicado %": pf_for_turbine * 100.0,
                "Fuente FP": wind_match["source"],
                "Columna viento": wind_match["wind_col"],
                "Nº turbinas": turbines,
                "Potencia instalada kW": installed_kw,
                "Generación mensual kWh": gen_month_total,
                "Generación anual kWh": gen_year_total,
                "Cobertura real %": coverage_real,
                "Cobertura útil %": useful_coverage,
                "Excedente mensual kWh": surplus_monthly,
                "CAPEX unitario aplicado CLP": unit_capex[name],
                "Fuente CAPEX": capex_source,
                "CAPEX CLP": capex_total,
                "CAPEX MM CLP": capex_total / 1_000_000,
                "LCOE CLP/kWh": lcoe,
                "Ahorro bruto anual CLP": gross_saving,
                "Ingreso excedente anual CLP": surplus_income,
                "O&M anual CLP": om_annual,
                "Beneficio neto anual CLP": benefit_net,
                "Payback años": payback,
                "Beneficio neto periodo CLP": benefit_20,
                "Diésel evitado L/año": diesel_avoided,
                "CO2 evitado t/año": co2_avoided,
                "Impacto superficial m2": surface,
            }
        )
    sim_df = pd.DataFrame(rows)
    sim_df["Score"] = (
        _telecom_score(sim_df["CAPEX CLP"]) * 0.30
        + _telecom_score(sim_df["Payback años"]) * 0.34
        + _telecom_score(sim_df["LCOE CLP/kWh"]) * 0.20
        + _telecom_score(sim_df["Cobertura útil %"], higher_is_better=True) * 0.10
        + _telecom_score(sim_df["CO2 evitado t/año"], higher_is_better=True) * 0.06
    ) * 100.0
    recommended = sim_df.sort_values("Score", ascending=False, na_position="last").iloc[0]
    st.session_state["telecom_00_analysis_sim_df"] = sim_df.to_dict("records")
    st.session_state["telecom_00_analysis_recommended"] = recommended.to_dict()
    st.session_state["telecom_00_analysis_context"] = {
        "monthly_consumption": float(monthly_consumption),
        "target_coverage": float(target_coverage),
        "safety_margin": float(safety_margin),
        "project_life": float(project_life),
        "weighted_cost": float(weighted_cost),
        "surplus_price": float(surplus_price),
        "surplus_factor": float(surplus_factor),
        "bos_pct": float(bos_pct),
        "om_pct": float(om_pct),
        "degradation": float(degradation),
        "recommended_fp": float(recommended.get("FP aplicado %", np.nan)),
        "recommended_fp_source": str(recommended.get("Fuente FP", "")),
        "recommended_wind_column": str(recommended.get("Columna viento", "")),
        "fp_by_alternative": {
            str(row["Alternativa"]): {
                "fp": float(row.get("FP aplicado %", np.nan)),
                "source": str(row.get("Fuente FP", "")),
                "wind_column": str(row.get("Columna viento", "")),
                "height": float(row.get("Altura total m", np.nan)),
            }
            for _, row in sim_df.iterrows()
        },
    }
    current_annual_energy_cost = monthly_consumption * 12.0 * weighted_cost

    def cumulative_savings_chart(row: pd.Series, height: int = 360) -> go.Figure:
        years_axis = np.arange(0, int(project_life) + 1)
        annual_benefit = max(float(row.get("Beneficio neto anual CLP", 0.0) or 0.0), 0.0)
        capex_value = max(float(row.get("CAPEX CLP", 0.0) or 0.0), 0.0)
        cumulative = np.array([
            sum(annual_benefit * ((1.0 - degradation / 100.0) ** y) for y in range(int(year)))
            for year in years_axis
        ])
        after_capex = cumulative - capex_value
        payback_value = float(row.get("Payback años", np.nan))
        fig = go.Figure()
        fig.add_trace(
            go.Scatter(
                x=years_axis,
                y=cumulative / 1_000_000,
                name="Beneficio acumulado",
                mode="lines+markers",
                line=dict(color=palette["orange"], width=3.6),
                marker=dict(size=7, color=palette["orange"], line=dict(color="#ffffff", width=1.4)),
                hovertemplate="Año %{x}<br>Beneficio acumulado: %{y:.1f} MM CLP<extra></extra>",
            )
        )
        fig.add_trace(
            go.Scatter(
                x=years_axis,
                y=after_capex / 1_000_000,
                name="Neto después CAPEX",
                mode="lines+markers",
                line=dict(color=palette["ink"], width=3.8),
                marker=dict(size=7, color=palette["ink"], line=dict(color="#ffffff", width=1.4)),
                fill="tozeroy",
                fillcolor="rgba(117,169,184,.16)",
                hovertemplate="Año %{x}<br>Neto post CAPEX: %{y:.1f} MM CLP<extra></extra>",
            )
        )
        fig.add_hline(y=0, line_color=palette["text"], line_width=1, opacity=0.55)
        if np.isfinite(payback_value) and payback_value > 0:
            payback_x = max(0.0, min(payback_value, float(project_life)))
            fig.add_vline(x=payback_x, line_color=palette["orange"], line_dash="dash", annotation_text=f"Payback {years_label(payback_value)}", annotation_position="top right")
            fig.add_trace(
                go.Scatter(
                    x=[payback_x],
                    y=[0],
                    name="Payback",
                    mode="markers+text",
                    marker=dict(size=18, color="#ffffff", line=dict(color=palette["orange"], width=4)),
                    text=[years_label(payback_value)],
                    textposition="bottom right",
                    textfont=dict(color=palette["text"], size=12),
                    hovertemplate=f"Payback: {years_label(payback_value)}<extra></extra>",
                )
            )
        fig.update_layout(xaxis=dict(title="Año de operación", range=[0, project_life]), yaxis=dict(title="MM CLP"))
        return tune_fig(fig, height)

    def decision_map_chart(map_df: pd.DataFrame, selected_turbine: str, height: int = 370) -> go.Figure:
        fig = go.Figure()
        sizes = np.clip(pd.to_numeric(map_df["Cobertura real %"], errors="coerce").fillna(0.0) / 4.0, 18, 44)
        fig.add_trace(
            go.Scatter(
                x=map_df["CAPEX MM CLP"],
                y=map_df["Payback años"],
                mode="markers+text",
                text=map_df["Alternativa"],
                textposition=["top left", "bottom right", "top right", "bottom left", "top center"][: len(map_df)],
                marker=dict(
                    size=sizes,
                    color=map_df["Score"],
                    colorscale=[[0, palette["pale"]], [0.55, palette["sky"]], [1, palette["ink"]]],
                    showscale=True,
                    colorbar=dict(title="Score"),
                    line=dict(color="#ffffff", width=2),
                ),
                customdata=np.stack([map_df["LCOE CLP/kWh"], map_df["Cobertura real %"]], axis=-1),
                hovertemplate="<b>%{text}</b><br>CAPEX: %{x:.1f} MM CLP<br>Payback: %{y:.1f} años<br>LCOE: %{customdata[0]:,.0f} CLP/kWh<br>Cobertura: %{customdata[1]:.0f}%<extra></extra>",
            )
        )
        selected_df = map_df[map_df["Alternativa"].astype(str) == str(selected_turbine)]
        if not selected_df.empty:
            selected_point = selected_df.iloc[0]
            fig.add_trace(
                go.Scatter(
                    x=[selected_point["CAPEX MM CLP"]],
                    y=[selected_point["Payback años"]],
                    mode="markers",
                    marker=dict(size=54, color="rgba(255,255,255,0)", line=dict(color=palette["orange"], width=4)),
                    hoverinfo="skip",
                    showlegend=False,
                )
            )
            fig.add_annotation(
                x=float(selected_point["CAPEX MM CLP"]),
                y=float(selected_point["Payback años"]),
                text="RECOMENDADA",
                showarrow=True,
                arrowhead=2,
                arrowcolor=palette["orange"],
                ax=0,
                ay=-48,
                font=dict(color=palette["orange"], size=11),
                bgcolor="#ffffff",
                bordercolor=palette["orange"],
                borderwidth=1,
                borderpad=4,
            )
        fig.add_vline(x=float(map_df["CAPEX MM CLP"].median()), line=dict(color=palette["sky"], width=1.8, dash="dot"))
        fig.add_hline(y=float(map_df["Payback años"].median()), line=dict(color=palette["sky"], width=1.8, dash="dot"))
        fig.add_annotation(
            xref="paper",
            yref="paper",
            x=0.02,
            y=0.98,
            text="Zona óptima = menor CAPEX y menor payback",
            showarrow=False,
            align="left",
            font=dict(color=palette["text"], size=12),
            bgcolor="rgba(255,255,255,.88)",
            bordercolor="rgba(117,169,184,.35)",
            borderwidth=1,
            borderpad=5,
        )
        fig.update_layout(xaxis=dict(title="CAPEX total (MM CLP)", rangemode="tozero"), yaxis=dict(title="Payback (años)", rangemode="tozero"))
        return tune_fig(fig, height)

    def waterfall_chart(row: pd.Series, height: int = 360) -> go.Figure:
        current_cost = max(float(current_annual_energy_cost or 0.0), 0.0)
        wind_saving = max(float(row.get("Ahorro bruto anual CLP", 0.0) or 0.0), 0.0)
        surplus_income = max(float(row.get("Ingreso excedente anual CLP", 0.0) or 0.0), 0.0)
        om_cost = max(float(row.get("O&M anual CLP", 0.0) or 0.0), 0.0)
        show_surplus = (wind_saving + surplus_income) > 0 and surplus_income / (wind_saving + surplus_income) >= 0.05
        net_final = max(current_cost - wind_saving - surplus_income + om_cost, 0.0)
        labels = ["Costo actual", "Ahorro eólico"]
        values = [current_cost / 1_000_000, -wind_saving / 1_000_000]
        measures = ["absolute", "relative"]
        text = [f"{current_cost/1_000_000:.1f} MM", f"-{wind_saving/1_000_000:.1f} MM"]
        if show_surplus:
            labels.append("Ingreso excedentes")
            values.append(-surplus_income / 1_000_000)
            measures.append("relative")
            text.append(f"-{surplus_income/1_000_000:.1f} MM")
        labels.extend(["O&M anual", "Costo neto final"])
        values.extend([om_cost / 1_000_000, net_final / 1_000_000])
        measures.extend(["relative", "total"])
        text.extend([f"+{om_cost/1_000_000:.1f} MM", f"{net_final/1_000_000:.1f} MM"])
        fig = go.Figure(
            go.Waterfall(
                name="Waterfall económico",
                measure=measures,
                x=labels,
                y=values,
                text=text,
                textposition="outside",
                connector={"line": {"color": "rgba(100,116,139,.35)", "width": 1.2, "dash": "dot"}},
                increasing={"marker": {"color": palette["copper"], "line": {"color": "#ffffff", "width": 1.2}}},
                decreasing={"marker": {"color": palette["sky"], "line": {"color": "#ffffff", "width": 1.2}}},
                totals={"marker": {"color": palette["ink"], "line": {"color": "#ffffff", "width": 1.4}}},
                hovertemplate="<b>%{x}</b><br>Impacto: %{y:.1f} MM CLP/año<extra></extra>",
            )
        )
        fig.add_hline(y=0, line_color="rgba(32,56,79,.45)", line_width=1)
        fig.update_layout(yaxis=dict(title="MM CLP/año", rangemode="tozero"), xaxis=dict(title=None), showlegend=False)
        return tune_fig(fig, height)

    def wind_sensitivity_chart(height: int = 350) -> go.Figure:
        rec_base_fp = float(recommended.get("FP aplicado %", plant_factor))
        fp_range = np.array([
            max(5.0, rec_base_fp - 15),
            max(5.0, rec_base_fp - 10),
            max(5.0, rec_base_fp - 5),
            rec_base_fp,
            min(85.0, rec_base_fp + 5),
            min(85.0, rec_base_fp + 10),
        ])
        fig = go.Figure()
        rec_name = str(recommended["Alternativa"])
        for _, base_row in sim_df.iterrows():
            name = str(base_row["Alternativa"])
            kw = turbine_kw[name]
            turbines = int(base_row["Nº turbinas"])
            capex_value = float(base_row["CAPEX CLP"])
            om_value = float(base_row["O&M anual CLP"])
            y_values = []
            for fp in fp_range:
                eff = fp / 100.0
                gen_m = kw * 8760.0 * eff / 12.0 * turbines
                useful_m = min(gen_m, monthly_consumption)
                surplus_m = max(gen_m - monthly_consumption, 0.0)
                benefit = max(useful_m * 12.0 * weighted_cost + surplus_m * 12.0 * surplus_price * surplus_factor - om_value, 0.0)
                y_values.append(capex_value / benefit if benefit > 0 else np.nan)
            is_rec = name == rec_name
            fig.add_trace(
                go.Scatter(
                    x=fp_range,
                    y=y_values,
                    mode="lines+markers+text" if is_rec else "lines+markers",
                    name=name,
                    line=dict(color=palette["orange"] if is_rec else "rgba(148,163,184,.45)", width=4 if is_rec else 2),
                    marker=dict(size=10 if is_rec else 6, color="#ffffff" if is_rec else "rgba(148,163,184,.75)", line=dict(color=palette["orange"] if is_rec else "rgba(148,163,184,.45)", width=2 if is_rec else 1)),
                    text=[years_label(v) if is_rec else "" for v in y_values],
                    textposition="top center",
                    hovertemplate="<b>%{fullData.name}</b><br>FP: %{x:.1f}%<br>Payback: %{y:.1f} años<extra></extra>",
                )
            )
        fig.add_vline(x=rec_base_fp, line_dash="dash", line_color=palette["ink"], annotation_text="Escenario base")
        fig.update_layout(xaxis=dict(title="Factor planta real (%)"), yaxis=dict(title="Payback (años)", rangemode="tozero"))
        return tune_fig(fig, height)

    score_width = max(0, min(100, float(recommended["Score"])))
    rec_generation = float(recommended["Generación mensual kWh"])
    rec_surplus = float(recommended["Excedente mensual kWh"])
    rec_benefit = float(recommended["Beneficio neto anual CLP"])
    rec_capex = float(recommended["CAPEX MM CLP"])
    rec_coverage = float(recommended["Cobertura real %"])
    rec_fp = float(recommended.get("FP aplicado %", plant_factor))
    rec_height = float(recommended.get("Altura total m", np.nan))
    rec_height_text = f"{rec_height:.1f} m" if np.isfinite(rec_height) else "altura no disponible"
    rec_fp_source = str(recommended.get("Fuente FP", "Input base"))
    rec_wind_col = str(recommended.get("Columna viento", "") or "")
    rec_wind_text = rec_fp_source

    def monthly_generation_consumption_df(row: pd.Series) -> pd.DataFrame:
        month_labels = ["Ene", "Feb", "Mar", "Abr", "May", "Jun", "Jul", "Ago", "Sept", "Oct", "Nov", "Dic"]
        turbines_count = int(row.get("Nº turbinas", 0) or 0)
        height_value = float(row.get("Altura total m", np.nan))
        base_monthly_generation = float(row.get("Generación mensual kWh", 0.0) or 0.0)
        generation_source_base = str(row.get("Fuente FP", "Promedio mensual calculado") or "Promedio mensual calculado")
        use_curve_03_generation = "03 curva" in generation_source_base.casefold()
        monthly_rows = []
        for month in range(1, 13):
            generation_per_turbine = np.nan
            if (not use_curve_03_generation) and (not wind_monthly_profile.empty) and np.isfinite(height_value):
                month_profile = wind_monthly_profile[np.isclose(wind_monthly_profile["Mes"].astype(float), float(month), atol=0.001)].copy()
                if not month_profile.empty:
                    heights = month_profile["Altura m"].to_numpy(dtype=float)
                    monthly_energy = month_profile["Energía mensual neta kWh por turbina"].to_numpy(dtype=float)
                    valid = np.isfinite(heights) & np.isfinite(monthly_energy)
                    heights = heights[valid]
                    monthly_energy = monthly_energy[valid]
                    order = np.argsort(heights)
                    heights = heights[order]
                    monthly_energy = monthly_energy[order]
                    if len(heights) == 1:
                        generation_per_turbine = float(monthly_energy[0])
                    elif len(heights) > 1:
                        generation_per_turbine = float(np.interp(height_value, heights, monthly_energy, left=monthly_energy[0], right=monthly_energy[-1]))
            generation_total = generation_per_turbine * turbines_count if np.isfinite(generation_per_turbine) else base_monthly_generation
            generation_source = (
                "09_Viento mensual por altura"
                if np.isfinite(generation_per_turbine)
                else generation_source_base
            )
            covered = min(generation_total, monthly_consumption)
            surplus = max(generation_total - monthly_consumption, 0.0)
            gap = max(monthly_consumption - generation_total, 0.0)
            monthly_rows.append(
                {
                    "Mes": month_labels[month - 1],
                    "Mes num": month,
                    "Generación kWh": generation_total,
                    "Consumo cubierto kWh": covered,
                    "Excedente kWh": surplus,
                    "Brecha kWh": gap,
                    "Balance kWh": generation_total - monthly_consumption,
                    "Consumo sitio kWh": monthly_consumption,
                    "Cobertura %": generation_total / monthly_consumption * 100.0 if monthly_consumption > 0 else 0.0,
                    "Fuente": generation_source,
                }
            )
        return pd.DataFrame(monthly_rows)

    def monthly_generation_consumption_chart(row: pd.Series, height: int = 380) -> go.Figure:
        month_labels = ["Ene", "Feb", "Mar", "Abr", "May", "Jun", "Jul", "Ago", "Sept", "Oct", "Nov", "Dic"]
        monthly_df = monthly_generation_consumption_df(row)
        fig = go.Figure()
        fig.add_trace(
            go.Bar(
                x=monthly_df["Mes"],
                y=monthly_df["Consumo sitio kWh"],
                name="Consumo sitio",
                marker_color="rgba(148,163,184,.28)",
                offsetgroup="consumo",
                customdata=np.stack([monthly_df["Generación kWh"], monthly_df["Cobertura %"], monthly_df["Balance kWh"]], axis=-1),
                hovertemplate="<b>%{x}</b><br>Consumo: %{y:,.0f} kWh<br>Generación: %{customdata[0]:,.0f} kWh<br>Cobertura: %{customdata[1]:.0f}%<br>Balance: %{customdata[2]:+,.0f} kWh<extra></extra>",
            )
        )
        fig.add_trace(
            go.Bar(
                x=monthly_df["Mes"],
                y=monthly_df["Generación kWh"],
                name="Generación 03",
                marker_color=palette["orange"],
                offsetgroup="generacion",
                customdata=np.stack([monthly_df["Consumo cubierto kWh"], monthly_df["Excedente kWh"], monthly_df["Brecha kWh"], monthly_df["Cobertura %"]], axis=-1),
                hovertemplate="<b>%{x}</b><br>Generación: %{y:,.0f} kWh<br>Cubierto: %{customdata[0]:,.0f} kWh<br>Excedente: %{customdata[1]:,.0f} kWh<br>Brecha: %{customdata[2]:,.0f} kWh<br>Cobertura: %{customdata[3]:.0f}%<extra></extra>",
            )
        )
        fig.add_trace(
            go.Bar(
                x=monthly_df["Mes"],
                y=monthly_df["Balance kWh"].abs(),
                name="Brecha / excedente",
                marker_color=np.where(monthly_df["Balance kWh"] >= 0, palette["sky"], "rgba(148,163,184,.55)"),
                offsetgroup="balance",
                customdata=np.stack([monthly_df["Balance kWh"], monthly_df["Excedente kWh"], monthly_df["Brecha kWh"]], axis=-1),
                hovertemplate="<b>%{x}</b><br>Balance: %{customdata[0]:+,.0f} kWh<br>Excedente: %{customdata[1]:,.0f} kWh<br>Brecha: %{customdata[2]:,.0f} kWh<extra></extra>",
            )
        )
        fig.add_trace(
            go.Scatter(
                x=monthly_df["Mes"],
                y=monthly_df["Cobertura %"],
                name="Cobertura",
                yaxis="y2",
                mode="lines+markers+text",
                line=dict(color=palette["ink"], width=3.2),
                marker=dict(size=9, color="#ffffff", line=dict(color=palette["ink"], width=2)),
                text=[f"{value:.0f}%" for value in monthly_df["Cobertura %"]],
                textposition="top center",
                hovertemplate="<b>%{x}</b><br>Cobertura: %{y:.0f}%<extra></extra>",
            )
        )
        source_note = str(monthly_df["Fuente"].iloc[0]) if not monthly_df.empty else "Sin fuente"
        annual_generation = float(monthly_df["Generación kWh"].sum() or 0.0)
        annual_consumption = float(monthly_df["Consumo sitio kWh"].sum() or 0.0)
        annual_coverage = annual_generation / annual_consumption * 100.0 if annual_consumption > 0 else 0.0
        fig.add_annotation(
            xref="paper",
            yref="paper",
            x=0.01,
            y=1.18,
            text=f"Fuente: {source_note}<br>Año: {annual_generation:,.0f} kWh generados / {annual_consumption:,.0f} kWh consumo · cobertura {annual_coverage:.0f}%".replace(",", "."),
            showarrow=False,
            align="left",
            bgcolor="rgba(255,255,255,.88)",
            bordercolor="rgba(117,169,184,.35)",
            borderwidth=1,
            borderpad=4,
            font=dict(color=palette["text"], size=11),
        )
        fig.update_layout(
            barmode="group",
            xaxis=dict(title=None, categoryorder="array", categoryarray=month_labels),
            yaxis=dict(title="kWh/mes", rangemode="tozero"),
            yaxis2=dict(title="Cobertura", overlaying="y", side="right", ticksuffix="%", rangemode="tozero", showgrid=False),
        )
        fig = tune_fig(fig, height)
        fig.update_layout(legend=dict(orientation="h", y=1.10, x=0, title=None))
        return fig

    def generation_audit_chart(row: pd.Series, height: int = 300) -> go.Figure:
        monthly_df = monthly_generation_consumption_df(row)
        generation = float(monthly_df["Generación kWh"].sum() or 0.0)
        consumption = float(monthly_df["Consumo sitio kWh"].sum() or 0.0)
        covered = float(monthly_df["Consumo cubierto kWh"].sum() or 0.0)
        surplus = float(monthly_df["Excedente kWh"].sum() or 0.0)
        gap = float(monthly_df["Brecha kWh"].sum() or 0.0)
        fig = go.Figure()
        fig.add_trace(go.Bar(
            x=["Generación 03", "Consumo anual", "Consumo cubierto", "Excedente", "Brecha"],
            y=[generation, consumption, covered, surplus, gap],
            marker_color=[palette["orange"], "rgba(148,163,184,.35)", palette["sky"], palette["copper"], "rgba(148,163,184,.65)"],
            text=[f"{value:,.0f}".replace(",", ".") for value in [generation, consumption, covered, surplus, gap]],
            textposition="outside",
            hovertemplate="<b>%{x}</b><br>%{y:,.0f} kWh/año<extra></extra>",
        ))
        fig.add_annotation(
            xref="paper",
            yref="paper",
            x=0.01,
            y=1.12,
            text="Auditoría anual: generación viene de pestaña 03; el balance separa cobertura útil, excedente y brecha.",
            showarrow=False,
            align="left",
            font=dict(color=palette["text"], size=11),
            bgcolor="rgba(255,255,255,.88)",
            bordercolor="rgba(117,169,184,.35)",
            borderwidth=1,
            borderpad=4,
        )
        fig.update_layout(xaxis=dict(title=None), yaxis=dict(title="kWh/año", rangemode="tozero"), showlegend=False)
        return tune_fig(fig, height)

