        fig_econ.update_layout(xaxis=dict(categoryorder="array", categoryarray=turbine_order), yaxis=dict(title="CAPEX (MM CLP)", rangemode="tozero"), yaxis2=dict(title="LCOE (CLP/kWh)", overlaying="y", side="right", showgrid=False))
